-- Poems batch 344
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('24bdeea2-1379-42e9-b80c-6a1f97a9a49b','春雨中偶成四首  其三','張耒','宋','宋诗','song-poetry','','[]','天低芳草接浮雲，萬柳含烟翠不分。',32,'全唐诗/poet.song.65000.json','["天低芳草接浮雲，萬柳含烟翠不分。", "燕子歸時花遍落，暮雲和雨入黄昏。"]'),
('98fc607f-cafa-4029-823a-51ca92cd41c6','春雨中偶成四首  其四','張耒','宋','宋诗','song-poetry','','[]','春陰只與睡相宜，卧聽鳴禽語復飛。',32,'全唐诗/poet.song.65000.json','["春陰只與睡相宜，卧聽鳴禽語復飛。", "一縷斷香浮不散，何人深院晝熏衣。"]'),
('d6a45b1a-3807-485a-8454-01d6d8a78ee0','春詞二首  其一','張耒','宋','宋诗','song-poetry','','[]','殘紅新綠間鞦韆，寒食園林人意闌。',32,'全唐诗/poet.song.65000.json','["殘紅新綠間鞦韆，寒食園林人意闌。", "一陣春寒花上起，畫廊連夜雨珊珊。"]'),
('04fa2aa5-d5b8-4d47-8e3d-abd74a6bf00b','春詞二首  其二','張耒','宋','宋诗','song-poetry','','[]','靄靄芳園誰氏家，朱門橫鎖夕陽斜。',32,'全唐诗/poet.song.65000.json','["靄靄芳園誰氏家，朱門橫鎖夕陽斜。", "鳩鳴鵲噪閒庭館，盡日春風吹百花。"]'),
('b5143576-bf33-41a4-b2e9-7f645b5289de','遣興','張耒','宋','宋诗','song-poetry','','[]','百感摧傷强對春，看花花畔獨沾巾。',32,'全唐诗/poet.song.65000.json','["百感摧傷强對春，看花花畔獨沾巾。", "祇應閉目林中坐，須學無言壁下人。"]'),
('364a63e0-a1eb-4fbf-b69e-58deb19f4017','潮水二首  其一','張耒','宋','宋诗','song-poetry','','[]','水滿清淮自在流，落花吹盡浪悠悠。',32,'全唐诗/poet.song.65000.json','["水滿清淮自在流，落花吹盡浪悠悠。", "總將春雨爲春淚，未比思君一半愁。"]'),
('781e9cb8-75fb-4c9c-88c1-5173ec5b3168','潮水二首  其二','張耒','宋','宋诗','song-poetry','','[]','近來消息愈堪猜，飛鳥無情不肯迴。',32,'全唐诗/poet.song.65000.json','["近來消息愈堪猜，飛鳥無情不肯迴。", "惟有清淮慰人意，春流日日自東來。"]'),
('91c6daf7-7211-4cf3-95ac-a734e3abce38','夏日池上三首  其一','張耒','宋','宋诗','song-poetry','','[]','新蟬上樹空遺蛻，野雀哺雛爭小蟲。',32,'全唐诗/poet.song.65000.json','["新蟬上樹空遺蛻，野雀哺雛爭小蟲。", "粉沾衣袖竹枝雨，香滿水亭荷葉風。"]'),
('873545f2-23fb-4109-acfa-4d17c0c98141','夏日池上三首  其二','張耒','宋','宋诗','song-poetry','','[]','落日鳴蟬夏木荒，芙蓉半落柳成行。',32,'全唐诗/poet.song.65000.json','["落日鳴蟬夏木荒，芙蓉半落柳成行。", "何人紈扇生新恨，亭館迎秋夜夜凉。"]'),
('4cc17d87-e9a8-4ac4-b1ce-85a10c9d5438','夏日池上三首  其三','張耒','宋','宋诗','song-poetry','','[]','拒霜灼灼欲破紅，夜來雨落荒蘭叢。',32,'全唐诗/poet.song.65000.json','["拒霜灼灼欲破紅，夜來雨落荒蘭叢。", "空亭無人日色午，但聽桐葉驚秋風。"]'),
('4662cbc1-7738-46a6-81e0-d28393765daa','秋日即事三首  其一','張耒','宋','宋诗','song-poetry','','[]','支離卧病不知秋，暑退初驚大火流。',32,'全唐诗/poet.song.65000.json','["支離卧病不知秋，暑退初驚大火流。", "蟋蟀知時鳴近壁，銀河照夜直當樓。"]'),
('2d68ba9e-d237-46a4-a5ce-5a620d25ee49','秋日即事三首  其二','張耒','宋','宋诗','song-poetry','','[]','蕭條歲晚搔雙鬢，流落天涯念舊遊。',32,'全唐诗/poet.song.65000.json','["蕭條歲晚搔雙鬢，流落天涯念舊遊。", "惟有醉來心暫展，無錢沽酒合長愁。"]'),
('14b0c406-72b7-45cd-8ab1-ec53209fbfbe','秋日即事三首  其三','張耒','宋','宋诗','song-poetry','','[]','蕭蕭衰草傍牆生，中有寒蟲白日鳴。',32,'全唐诗/poet.song.65000.json','["蕭蕭衰草傍牆生，中有寒蟲白日鳴。", "秋物荒凉禾稼熟，悠悠驅馬水邊行。"]'),
('29f45bc1-ab28-4823-9cec-eba6cea04dbb','秋雨二首  其一','張耒','宋','宋诗','song-poetry','','[]','南山雲起滿庭陰，簾幕初凉七月深。',32,'全唐诗/poet.song.65000.json','["南山雲起滿庭陰，簾幕初凉七月深。", "桃子壓枝桐葉老，連綿風雨作愁霖。"]'),
('2c0cfeef-670d-467c-b6d6-3fe341d07e84','秋雨二首  其二','張耒','宋','宋诗','song-poetry','','[]','離披衰柳已無蟬，黄葉閉門風雨天。',32,'全唐诗/poet.song.65000.json','["離披衰柳已無蟬，黄葉閉門風雨天。", "陶令無錢難得醉，竹窗過午枕書眠。"]'),
('6c5f64ba-007a-417c-9b93-bf864ba54c27','秋夜寄遠','張耒','宋','宋诗','song-poetry','','[]','秋晚蕭條風露清，星河耿耿漏丁丁。',32,'全唐诗/poet.song.65000.json','["秋晚蕭條風露清，星河耿耿漏丁丁。", "祇應新月頻相見，長向玉樓東畔生。"]'),
('5cdf1b57-e53e-4c5f-9ad0-1c2cef39a21b','秋夜','張耒','宋','宋诗','song-poetry','','[]','微雲淡月夜朦朧，幽草蟲鳴樹影中。',32,'全唐诗/poet.song.65000.json','["微雲淡月夜朦朧，幽草蟲鳴樹影中。", "不待南城吹鼓角，桐聲長報五更風。"]'),
('a7006a12-a82e-4b50-a706-aafa6f8f0b44','遠思','張耒','宋','宋诗','song-poetry','','[]','裊裊霜風吹碧梧，孤城殘角奏單于。',32,'全唐诗/poet.song.65000.json','["裊裊霜風吹碧梧，孤城殘角奏單于。", "山川浩蕩愁千里，樓閣黄昏月一梳。"]'),
('21927f77-16bf-474e-8902-d961987f4581','懷竟陵蓮花','張耒','宋','宋诗','song-poetry','','[]','景湖門外有汀洲，灼灼紅蓮照碧流。',32,'全唐诗/poet.song.65000.json','["景湖門外有汀洲，灼灼紅蓮照碧流。", "公子不歸時節晚，雨枝風葉卧清秋。"]'),
('141f72ba-beca-42a8-a6e4-30204653b48d','懷陸羽井','張耒','宋','宋诗','song-poetry','','[]','寒泉背石老松根，禪室幽人古像存。',32,'全唐诗/poet.song.65000.json','["寒泉背石老松根，禪室幽人古像存。", "長恨千年無屈宋，楚招難與此遺魂。"]'),
('38f43066-a807-412f-9d6b-8a057e359eda','冬日懷竟陵管氏梅橋四首  其一','張耒','宋','宋诗','song-poetry','','[]','旅居澤國小園林，千里相望歲暮心。',32,'全唐诗/poet.song.65000.json','["旅居澤國小園林，千里相望歲暮心。", "想見竟陵殘雪裏，新梅點雪橘垂金。"]'),
('72e58057-8ffc-460e-a8a7-7831cd6cda24','冬日懷竟陵管氏梅橋四首  其二','張耒','宋','宋诗','song-poetry','','[]','小小園林點點梅，如今綽約爲誰開。',32,'全唐诗/poet.song.65000.json','["小小園林點點梅，如今綽約爲誰開。", "只應清夜新霜裏，依舊橫斜倒影來。"]'),
('2c11d7d3-7f6f-4a81-a701-c91e2d97a01c','冬日懷竟陵管氏梅橋四首  其三','張耒','宋','宋诗','song-poetry','','[]','他日華陵跡已陳，嘉辰懷舊一銷魂。',32,'全唐诗/poet.song.65000.json','["他日華陵跡已陳，嘉辰懷舊一銷魂。", "小園幽徑誰相念，應有新梅覓故人。"]'),
('0368423e-7113-42d1-b162-12e901c75b9a','冬日懷竟陵管氏梅橋四首  其四','張耒','宋','宋诗','song-poetry','','[]','堂下幽芳自可人，北風一爲屏埃塵。',32,'全唐诗/poet.song.65000.json','["堂下幽芳自可人，北風一爲屏埃塵。", "上元簪珥玲瓏玉，却曳青霞霜女裙。"]'),
('f2bd7eff-178c-4d2e-9ced-3c80d717314e','厄臺寺三首  其一','張耒','宋','宋诗','song-poetry','','[]','諸佛蒼然照殿楹，圓光明滿自然燈。',32,'全唐诗/poet.song.65000.json','["諸佛蒼然照殿楹，圓光明滿自然燈。", "千年遺事無人問，館後高眠久屬僧。"]'),
('48d562d0-9e07-46c6-a87d-261f80f78995','厄臺寺三首  其二','張耒','宋','宋诗','song-poetry','','[]','峨嵋前約已成空，風雨蕭蕭送暮鐘。',32,'全唐诗/poet.song.65000.json','["峨嵋前約已成空，風雨蕭蕭送暮鐘。", "何用忘機來問話，不如松下謁癡龍。"]'),
('904ebb76-9a74-4ed2-b1f1-a00812b0212e','厄臺寺三首  其三','張耒','宋','宋诗','song-poetry','','[]','世味嗟予淡莫加，更將詩句寄烟霞。',32,'全唐诗/poet.song.65000.json','["世味嗟予淡莫加，更將詩句寄烟霞。", "自憐落筆無好字，不及揚州王謝家。"]'),
('181e00a8-2e1d-46da-b456-df3e645d45ab','過蘄澤','張耒','宋','宋诗','song-poetry','','[]','雄吞六國弱秦强，壯士逡巡野水傍。',32,'全唐诗/poet.song.65000.json','["雄吞六國弱秦强，壯士逡巡野水傍。", "耕叟不知鴻鵠志，笑觀宮室忤陳王。"]'),
('6b1e190b-fbc0-4ae9-933c-cae19f29b8b8','崇化寺三首  其一','張耒','宋','宋诗','song-poetry','','[]','樓殿沉沉鎖夜烟，秋燈一點佛龕前。',32,'全唐诗/poet.song.65000.json','["樓殿沉沉鎖夜烟，秋燈一點佛龕前。", "梧桐葉上三更雨，亦有愁人獨自眠。"]'),
('0128eb87-e753-4b7c-ad97-5e852e0ee1ad','崇化寺三首  其二','張耒','宋','宋诗','song-poetry','','[]','白髮荆州嘆滯淫，吳衣重杵洛城砧。',32,'全唐诗/poet.song.65000.json','["白髮荆州嘆滯淫，吳衣重杵洛城砧。", "遣愁莫上高樓望，只有秋來晝日陰。"]'),
('b602e27c-a215-46e0-9af7-8853d52a27ff','崇化寺三首  其三','張耒','宋','宋诗','song-poetry','','[]','零落宮牆官樹秋，行人東去路悠悠。',32,'全唐诗/poet.song.65000.json','["零落宮牆官樹秋，行人東去路悠悠。", "祇應樓下邯鄲路，亦有離人對此愁。"]'),
('d330e915-7240-40b5-bf7a-2efad9521c07','偶成','張耒','宋','宋诗','song-poetry','','[]','漫學文章弊性靈，屠龍藝就誤平生。',32,'全唐诗/poet.song.65000.json','["漫學文章弊性靈，屠龍藝就誤平生。", "翩翩仕路新冠蓋，何用揚雄强作經。"]'),
('59d7dd5a-1a2c-4675-95d3-6d59b9e1bc2c','贈趙簿景平二首  其一','張耒','宋','宋诗','song-poetry','','[]','明道新墳草已春，遺風猶得見門人。',32,'全唐诗/poet.song.65000.json','["明道新墳草已春，遺風猶得見門人。", "定知魯國衣冠異，盡戴林宗折角巾。"]'),
('ec84e380-508f-44b1-a236-aa186bb0f204','贈趙簿景平二首  其二','張耒','宋','宋诗','song-poetry','','[]','紛紛俗物久堪憎，愛子蕭蕭眉宇清。',32,'全唐诗/poet.song.65000.json','["紛紛俗物久堪憎，愛子蕭蕭眉宇清。", "莫嘆青衫掩事業，白頭卿相死無名。"]'),
('23694c64-1237-47f4-8158-836d6b8ed1f6','自遣四首  其一','張耒','宋','宋诗','song-poetry','','[]','是非得失一區區，蚊蚋啾啾共一壺。',32,'全唐诗/poet.song.65000.json','["是非得失一區區，蚊蚋啾啾共一壺。", "不學退之求羽翼，惟憑一夢到華胥。"]'),
('9bce2c95-41d9-49c8-9096-903626dc1d8f','自遣四首  其二','張耒','宋','宋诗','song-poetry','','[]','誰云造化本無情，利害乘除理甚平。',32,'全唐诗/poet.song.65000.json','["誰云造化本無情，利害乘除理甚平。", "莫逐衆情生慍喜，君看三四孰虧盈。"]'),
('337fc081-528a-44dd-a54c-bd3bf90d085d','自遣四首  其三','張耒','宋','宋诗','song-poetry','','[]','誰云至理宗無相，大道由來萬法兼。',32,'全唐诗/poet.song.65000.json','["誰云至理宗無相，大道由來萬法兼。", "且以聲音爲佛事，曉敲清磬誦華嚴。"]'),
('723b14bf-27a8-43ca-b890-c6c637b52bca','自遣四首  其四','張耒','宋','宋诗','song-poetry','','[]','浮世榮枯理易觀，不勞重取朽龜鑽。',32,'全唐诗/poet.song.65000.json','["浮世榮枯理易觀，不勞重取朽龜鑽。", "直應桃李繁華日，便把荆榛寂寞看。"]'),
('a776ba89-ea4a-47ff-b9ea-4ab51d068b2f','立秋二首  其一','張耒','宋','宋诗','song-poetry','','[]','西風嫋嫋木颼颼，身在江湖北岸州。',32,'全唐诗/poet.song.65000.json','["西風嫋嫋木颼颼，身在江湖北岸州。", "自古楚人詞最好，爲君重賦竟陵秋。"]'),
('8f00675c-277f-4041-b61b-b39fd26aa979','立秋二首  其二','張耒','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','對酒聊同楚人醉，哦詩惟聽越吟聲。',32,'全唐诗/poet.song.65000.json','["對酒聊同楚人醉，哦詩惟聽越吟聲。", "洞庭北岸孤城下，落月西風聽曉鶯。"]'),
('8f05af27-bf3a-4c8e-8642-a310394e793d','晚步靈壽寺後二首  其一','張耒','宋','宋诗','song-poetry','','[]','秋城草樹欲黄昏，微逕新晴菜甲新。',32,'全唐诗/poet.song.65000.json','["秋城草樹欲黄昏，微逕新晴菜甲新。", "便好灌園從老圃，此懷原是漢陰人。"]'),
('6993d35b-32f1-48a4-9006-bbbea3472aec','晚步靈壽寺後二首  其二','張耒','宋','宋诗','song-poetry','','[]','逢秋種菊尚殷勤，隙地侵尋欲過鄰。',32,'全唐诗/poet.song.65000.json','["逢秋種菊尚殷勤，隙地侵尋欲過鄰。", "便好採花供服餌，形容已似澤邊人。"]'),
('aaafe460-0433-4e1b-9cfe-45d60932e24d','感秋三絕  其一','張耒','宋','宋诗','song-poetry','','[]','秋思鄉愁兩苦辛，每臨西北望秋雲。',32,'全唐诗/poet.song.65000.json','["秋思鄉愁兩苦辛，每臨西北望秋雲。", "此生更老情終在，誰爲寄聲千里人。"]'),
('c09a1fc1-8466-48d5-89ee-7bab1c6bd354','感秋三絕  其二','張耒','宋','宋诗','song-poetry','','[]','楚天未白轉星河，樓角先吹出塞歌。',32,'全唐诗/poet.song.65000.json','["楚天未白轉星河，樓角先吹出塞歌。", "長愧侵床五更月，殷勤無計謝姮娥。"]'),
('4b00e773-bc64-460e-b537-a39e6bd24c1d','感秋三絕  其三','張耒','宋','宋诗','song-poetry','','[]','高林敗葉已颼颼，更有寒莎翠已收。',32,'全唐诗/poet.song.65000.json','["高林敗葉已颼颼，更有寒莎翠已收。", "若道神仙脫情累，如何獨唱感庭秋。"]'),
('4bf10396-5193-432a-9f8b-df9dffc92d06','局中聽雨','張耒','宋','宋诗','song-poetry','','[]','秋庭聽雨斷人聲，凉入衣裾秋意生。',32,'全唐诗/poet.song.65000.json','["秋庭聽雨斷人聲，凉入衣裾秋意生。", "臨水登山送歸語，憐君解有許多情。"]'),
('52047b0c-4d0a-4e6f-abde-03ad5af18c8b','夜思','張耒','宋','宋诗','song-poetry','','[]','萬聲沉寂漏丁東，金井欄干上暗空。',32,'全唐诗/poet.song.65000.json','["萬聲沉寂漏丁東，金井欄干上暗空。", "半夜西風人未覺，秋聲先報草根蟲。"]'),
