('210f200c-1a75-4700-b1ad-6879156565a5','和蘇适春雪八首  其一','張耒','宋','宋诗','song-poetry','','[]','春城北斗轉招摇，寒御初還陣尚囂。',32,'全唐诗/poet.song.66000.json','["春城北斗轉招摇，寒御初還陣尚囂。", "一夜雪聲欺布被，定知貧舍故相撩。"]'),
('73ea589c-1a13-4902-b481-bc19d44fbf9a','和蘇适春雪八首  其二','張耒','宋','宋诗','song-poetry','','[]','寒陣須憑酒解圍，閒官幸可典朝衣。',32,'全唐诗/poet.song.66000.json','["寒陣須憑酒解圍，閒官幸可典朝衣。", "一杯冷落憑誰勸，却有飛花舞入帷。"]'),
('13b4dd3b-49ac-4681-8cc2-15acf81d740d','和蘇适春雪八首  其三','張耒','宋','宋诗','song-poetry','','[]','白帝陰兵嚴羽衛，漢皇老傅振鬚眉。',32,'全唐诗/poet.song.66000.json','["白帝陰兵嚴羽衛，漢皇老傅振鬚眉。", "撒鹽飛絮渾粗俗，盡撥塵言賦好詩。"]'),
('6095e6ec-fd6b-4151-aba4-35ca6dc5807c','和蘇适春雪八首  其四','張耒','宋','宋诗','song-poetry','','[]','溪上泛舟成底事，庵前夜立意如何。',32,'全唐诗/poet.song.66000.json','["溪上泛舟成底事，庵前夜立意如何。", "爭知萬頃青青麥，絕勝黄河一尺波。"]'),
('0ab2aa5d-19bc-4c9b-892e-db835b5bd77b','和蘇适春雪八首  其五','張耒','宋','宋诗','song-poetry','','[]','不死松篁勞借問，未開桃李與催妝。',32,'全唐诗/poet.song.66000.json','["不死松篁勞借問，未開桃李與催妝。", "已饒艷女纖腰舞，偏犯貧儒百結裳。"]'),
('92990616-00d4-496a-9d39-ed61051d63b3','和蘇适春雪八首  其六','張耒','宋','宋诗','song-poetry','','[]','偏憎遊騎香蹄污，最稱佳人素手團。',32,'全唐诗/poet.song.66000.json','["偏憎遊騎香蹄污，最稱佳人素手團。", "方丈老翁容膝外，出門四顧盡漫漫。"]'),
('868b0456-4587-4970-813d-997fd0d8752c','和蘇适春雪八首  其七','張耒','宋','宋诗','song-poetry','','[]','山中景物最幽奇，祇欠夫君爲賦詩。',32,'全唐诗/poet.song.66000.json','["山中景物最幽奇，祇欠夫君爲賦詩。", "長憶東風吹女几，瓊瑶交貫碧瑠璃。"]'),
('6932a950-5114-418f-aa03-9327daac98f2','和蘇适春雪八首  其八','張耒','宋','宋诗','song-poetry','','[]','寒窗凍坐成何事，趣喚紅妝遣暖寒。',32,'全唐诗/poet.song.66000.json','["寒窗凍坐成何事，趣喚紅妝遣暖寒。", "却把吟腸盛美酒，更令柔指撥清彈。"]'),
('3cc250ce-692c-4998-afb8-440350a785f5','宿盧村逆旅','張耒','宋','宋诗','song-poetry','','[]','夜宿村南貧主人，入門桃李已殘春。',32,'全唐诗/poet.song.66000.json','["夜宿村南貧主人，入門桃李已殘春。", "無人折贈門前柳，佇立東風獨愴神。"]'),
('bfb4a123-5501-4e0e-a6d9-8cd9da91be7b','紺碧','張耒','宋','宋诗','song-poetry','','[]','紺碧遙空秋意生，深簷當午暑風清。',32,'全唐诗/poet.song.66000.json','["紺碧遙空秋意生，深簷當午暑風清。", "老翁睡起支頤坐，初聽新蟬第一聲。"]'),
('05f52776-2e38-4163-8330-53d1fb678076','真陽縣晝睡縣舍素絲堂','張耒','宋','宋诗','song-poetry','','[]','見君堂下小荷葉，驚我客中春已空。',32,'全唐诗/poet.song.66000.json','["見君堂下小荷葉，驚我客中春已空。", "一覺西堂亭午睡，悠悠春夢逐春風。"]'),
('e90ab780-5f29-4877-a6ee-823f7c26af8c','贈圓明老','張耒','宋','宋诗','song-poetry','','[]','一粥一齋年已老，千經萬論不留心。',32,'全唐诗/poet.song.66000.json','["一粥一齋年已老，千經萬論不留心。", "菩提本自非言說，默默知師得更深。"]'),
('773dfdac-daa4-435b-9ad0-ccacb4abce3d','方丈小山','張耒','宋','宋诗','song-poetry','','[]','窗外幽軒數步寬，小山幽石對巑岏。',32,'全唐诗/poet.song.66000.json','["窗外幽軒數步寬，小山幽石對巑岏。", "說知老子婆娑意，且作僧房一衲看。"]'),
('891bf424-e3c2-4b0f-b5b3-c9bda80941e4','秋末圭竇齋前菊盛開賦得絕句時秬出未歸','張耒','宋','宋诗','song-poetry','','[]','幽齋誰與破窮愁，蜀錦當軒爛不收。',32,'全唐诗/poet.song.66000.json','["幽齋誰與破窮愁，蜀錦當軒爛不收。", "白帝屬車千萬乘，玉輪金轂照清秋。"]'),
('fcc30678-fee4-4f27-a09d-80063a7b6528','秋移宛丘牡丹植圭竇齋前作二絕示秬秸和  其一','張耒','宋','宋诗','song-poetry','','[]','共我辭家似旅人，栽培莫怪倍殷勤。',32,'全唐诗/poet.song.66000.json','["共我辭家似旅人，栽培莫怪倍殷勤。", "明年太昊城中色，來作齊安江上春。"]'),
('0bd2f9cb-61c7-4ecd-b977-fc2b9e1f45ff','秋移宛丘牡丹植圭竇齋前作二絕示秬秸和  其二','張耒','宋','宋诗','song-poetry','','[]','千里相逢如故人，故栽庭下要相親。',32,'全唐诗/poet.song.66000.json','["千里相逢如故人，故栽庭下要相親。", "明年一笑東風裏，山杏江桃不當春。"]'),
('40cf99ab-fced-4476-9f4a-f23449bdcf5d','夢靈壽寺','張耒','宋','宋诗','song-poetry','','[]','客居有似鴻遵渚，鴻渚相看豈有情。',32,'全唐诗/poet.song.66000.json','["客居有似鴻遵渚，鴻渚相看豈有情。", "何事春來頻見夢，老僧談笑起相迎。"]'),
('7342ad64-5400-41a7-9569-4323a92ce3e6','聞鵯鵊','張耒','宋','宋诗','song-poetry','','[]','紙窗未白燭微明，鵯鵊枝頭一兩聲。',32,'全唐诗/poet.song.66000.json','["紙窗未白燭微明，鵯鵊枝頭一兩聲。", "却憶去年桃李後，淮陽旅舍聽殘更。"]'),
('8d599714-bf8e-4b08-a10a-f61bf3cd5112','甯子','張耒','宋','宋诗','song-poetry','','[]','甯子陽愚飽諳事，賈生慟哭漫多愁。',32,'全唐诗/poet.song.66000.json','["甯子陽愚飽諳事，賈生慟哭漫多愁。", "無言天道何須問，畢竟人間春復秋。"]'),
('347c3477-0600-43fb-a6e6-34b205d1ad04','摘芙蓉','張耒','宋','宋诗','song-poetry','','[]','今年古寺摘芙蓉，憔悴真成澤畔翁。',32,'全唐诗/poet.song.66000.json','["今年古寺摘芙蓉，憔悴真成澤畔翁。", "聊把一枝閒照酒，明年何處對霜紅。"]'),
('24cd0714-684e-4ff5-b5fd-34d82dbe19fa','悼亡九首  其一','張耒','宋','宋诗','song-poetry','','[]','菊花還似去年黄，一寸愁心萬事傷。',32,'全唐诗/poet.song.66000.json','["菊花還似去年黄，一寸愁心萬事傷。", "獨立高樓對殘日，秋風吹得淚千行。"]'),
('d4eed83f-378a-42b7-8fc4-d47017cdef97','悼亡九首  其二','張耒','宋','宋诗','song-poetry','','[]','遙夜新霜凋碧槐，三更寒月滿堂階。',32,'全唐诗/poet.song.66000.json','["遙夜新霜凋碧槐，三更寒月滿堂階。", "美人化作秋風去，只有清魂夢裏來。"]'),
('b8bcbd68-b634-4e32-8cae-fe6a05501c1b','悼亡九首  其三','張耒','宋','宋诗','song-poetry','','[]','千行垂淚對風烟，萬事傷心兒女前。',32,'全唐诗/poet.song.66000.json','["千行垂淚對風烟，萬事傷心兒女前。", "曉鏡不須催白髮，潘郎秋鬢久蕭然。"]'),
('4f4c0464-a837-4085-bb0a-15008de6a975','悼亡九首  其四','張耒','宋','宋诗','song-poetry','','[]','曉梳零亂髮星星，病眼昏昏怯夜燈。',32,'全唐诗/poet.song.66000.json','["曉梳零亂髮星星，病眼昏昏怯夜燈。", "烏几素屏雙草屨，百年從此學山僧。"]'),
('8d5f7abf-62a9-421d-b632-130b4bc8d141','悼亡九首  其五','張耒','宋','宋诗','song-poetry','','[]','新霜已重菊初殘，半死梧桐泣井闌。',32,'全唐诗/poet.song.66000.json','["新霜已重菊初殘，半死梧桐泣井闌。", "可是神傷即無淚，哭多清血也應乾。"]'),
('e928376a-56f3-4a0c-baa0-f8bf43a0e0db','悼亡九首  其六','張耒','宋','宋诗','song-poetry','','[]','亦知存沒等浮雲，鮮笑多悲失道真。',32,'全唐诗/poet.song.66000.json','["亦知存沒等浮雲，鮮笑多悲失道真。", "却恐荒唐齊物叟，鼓盆真是已傷神。"]'),
('661a96bd-8ce4-4d79-b5ae-f73628ed9349','悼亡九首  其七','張耒','宋','宋诗','song-poetry','','[]','山僧老去久忘情，笑我多悲白髮生。',32,'全唐诗/poet.song.66000.json','["山僧老去久忘情，笑我多悲白髮生。", "爲道人間具煩惱，早來林下共修行。"]'),
('c05fd760-4087-4779-94e7-d3af1be65421','悼亡九首  其八','張耒','宋','宋诗','song-poetry','','[]','嵩陽道出建春門，同入西都四見春。',32,'全唐诗/poet.song.66000.json','["嵩陽道出建春門，同入西都四見春。", "誰謂回頭隔存沒，斷腸今作獨歸人。"]'),
('d59bba26-df89-4c56-b5d0-61478db0720b','悼亡九首  其九','張耒','宋','宋诗','song-poetry','','[]','欲治煩惱更無方，只有頭陀理最長。',32,'全唐诗/poet.song.66000.json','["欲治煩惱更無方，只有頭陀理最長。", "不待存亡始知夢，故應交臂已凄凉。"]'),
('4f183f49-68ad-4c6f-8945-289cb3923ab8','欲知歸期近呈天啟','張耒','宋','宋诗','song-poetry','','[]','欲知歸期近，屈指不滿手。',96,'全唐诗/poet.song.66000.json','["欲知歸期近，屈指不滿手。", "豈無兒女心，惜此良邂逅。", "蔡郎吾未見，心已想雄秀。", "那知風雨夜，聽此龍劍吼。", "八荒一驥子，萬馬空在廄。", "鍾山浄名老，爲子不惜口。", "頗聞國士薦，固自君所有。", "惟應功名地，他日容老醜。"]'),
('33b6a125-7bd1-4179-abac-08e2a96c7795','无咎兄贈子方寺丞見約出院奉謁復用原韵上呈子方兼答无咎見及語','張耒','宋','宋诗','song-poetry','','[]','曹侯驥骨雙瞳方，流沙萬里志不忘。',352,'全唐诗/poet.song.66000.json','["曹侯驥骨雙瞳方，流沙萬里志不忘。", "讀書故山蘭蕙芳，咳唾不顧尚書郎。", "參軍朔方試所長，奮鬚决策服老蒼。", "願得一索縛狡狂，凱歌揉馘獻明堂。", "黄河東峙萬旗槍，義渠竟失先零羌。", "坐師失律無否臧，但恨不取東關糧。", "黄君詩力回魁岡，十客未得一登床。", "携君秀句展我旁，草書紙上蛟龍驤。", "謂我君舍城東隍，年來長嘯棄軍裝。", "載酒欲訪執戟揚，休日出門如矙亡。", "坐令耿耿願莫償，紫衣宣詔襆被囊。", "獻書貢士學與鄉，羅庭充屋書萬行。", "風鬃霧鬣簡驌驦，考評唐虞論夏商。", "相過近如蜂隔房，君家八斗陳思王。", "千年門戶有輝光，任城健將獰鬚黄。", "猗蘭之苗不敢香，家人寄衣秋晚凉。", "滯留華館付杯觴，天高月明新雁翔。", "明燈高談夜未央，屈指計日引領望。", "來時汗流今雨霜，重門事嚴御史章。", "頼君諧捷解色莊，還家有日未用忙。", "眉間黄色是何祥，晁侯約我走門牆。", "但無閉關休饋漿，莫以獸微弓弗張。"]'),
('047e63f1-4261-40b9-b213-d44627c8c773','次韵奉酬无咎兼呈慎思天啟','張耒','宋','宋诗','song-poetry','','[]','平生結交圓納方，過眼十人八九忘。',352,'全唐诗/poet.song.66000.json','["平生結交圓納方，過眼十人八九忘。", "畹蘭畝蕙幽谷芳，懶隨家奴諛五郎。", "苦饑方朔身漫長，顛毛種種顔欲蒼。", "誰謂勝癡端坐狂，清淮之陰一草堂。", "列筆作陣茶森槍，絕口平戎與破羌。", "百年如此計亦臧，何用竊食官倉糧。", "玄黄病足畏高岡，但願縮頸老支床。", "煌煌東壁日月旁，神仙鸞鳳爭騰驤。", "萬書落架城覆隍，牙籤如雲丹碧裝。", "晁侯再作班與揚，正始故在何曾亡。", "江湖十年願飽償，夜成七發光出囊。", "蘇公後出長卿鄉，爲君吳都無一行。", "世有伯樂生驌驦，肯使弭耳隨鹽商。", "鄧侯楚山深閨房，名走上國交侯王。", "朝隨日景夜燈光，包攬今古窮炎黄。", "吐詞分葩有國香，近君如雪六月凉。", "又似心醉醍醐觴，東南蔡子名飛翔。", "同隨天書拜未央，瑰奇宏傑萬夫望。", "頰牙凜凜有風霜，文如神鼎爛龍章。", "鍾山長齋讀老莊，論兵說佛兩俱忙。", "不夸得硯文字祥，但願破敵如頹牆。", "我窮乞酒更得漿，仰看三虎爭雄張。"]'),
('b7d47791-e652-4bc8-8ccb-fddcbef38efe','贈天啟友弟','張耒','宋','宋诗','song-poetry','','[]','桑弧蓬矢射四方，嬰孩立志長可忘。',344,'全唐诗/poet.song.66000.json','["桑弧蓬矢射四方，嬰孩立志長可忘。", "莫學兒女漫弄芳，豪氣當視交河郎。", "邊城入望千里長，臂韝時架角鷹蒼。", "搏捷仍放韓盧狂，麕鶉日暮隨登堂。", "往來絕藝精飛槍，餘勇猶足吞頑羌。", "讀書誰謂穀勝臧，盛時萬鍾遠餽糧。", "水輸長川陸登岡，垂弓在櫜弩在床。", "蔽扞入陣牌居旁，天馬馴工披甲驤。", "受降濬築修城隍，刀頭不惜千金裝。", "三十六將皆鷹揚，故境可容尺地亡。", "子頗自負當夙償，況復武庫踰書囊。", "惟我與子舊同鄉，友生固自騰雁行。", "更欲揚鞭向驌驦，豈但傳經如卜商。", "不見漢時張子房，身纔六尺佐時王。", "功業能依日月光，素書一卷初逢黄。", "異時破賊玉書香，當使相繼來西凉。", "時臣稱賀持壽觴，鴻鵠一舉橫飛翔。", "光陰應須及未央，不侯可忍點鬢霜。", "少年天子坐建章，寵待穰苴不顧莊。", "嚴兵待時雖未忙，黠虜授首先有祥。", "王師會看傅城牆，郊迎父老携壺漿。", "去病當時凱樂張。"]'),
('854ef2d0-361b-4702-a5f0-515299fbf466','詩呈同院諸公  其一','張耒','宋','宋诗','song-poetry','','[]','鄧侯讀書室，編簡自相依。',48,'全唐诗/poet.song.66000.json','["鄧侯讀書室，編簡自相依。", "胝手焚膏寫，瘡肩滿橐歸。", "業文從古有，裁句似公稀。", "欲挈空虛篋，從君乞貝璣。"]'),
('0ef61aab-988c-4596-9a07-6199b43399d2','詩呈同院諸公  其二','張耒','宋','宋诗','song-poetry','','[]','鄧子詩成癖，全分李杜光。',48,'全唐诗/poet.song.66000.json','["鄧子詩成癖，全分李杜光。", "楚風還屈宋，宮體變齊梁。", "蔡子辨焦尾，晁公懷智囊。", "三賢方鼎峙，安敢用吾長。"]'),
('490845bf-2a56-4176-9a7f-ba00fc82ca18','詩呈同院諸公  其三','張耒','宋','宋诗','song-poetry','','[]','我愧言詩賜，公真好學回。',48,'全唐诗/poet.song.66000.json','["我愧言詩賜，公真好學回。", "讎書芝閣上，藏史楚山隈。", "把酒論交裏，連房校藝來。", "知君懷水鏡，依頼免遺才。"]'),
('2f543c5d-5a99-4e20-8bab-6fcc0cf5bfc9','秋日同文館詩  其一','張耒','宋','宋诗','song-poetry','','[]','騎列千床直，雲羅萬卷齊。',48,'全唐诗/poet.song.66000.json','["騎列千床直，雲羅萬卷齊。", "舒妍交孔翠，爭味雜柤梨。", "白日諸侯貢，青春天老題。", "秋清文酒健，莫歎羽林閨。"]'),
('0da5a12f-61b6-436c-b6c2-1ed5d034e015','秋日同文館詩  其二','張耒','宋','宋诗','song-poetry','','[]','聲鳴皆出谷，觜距各爭場。',48,'全唐诗/poet.song.66000.json','["聲鳴皆出谷，觜距各爭場。", "鐵網收明月，霜鋩倒豫章。", "湛恩終錫宴，優禮合焚香。", "最苦讎書客，消愁頼杜康。"]'),
('dc8d0d44-6b9d-4b38-bd5c-5c87299f5a98','秋日同文館詩  其三','張耒','宋','宋诗','song-poetry','','[]','六街分夜鼓，鄰屋報朝雞。',48,'全唐诗/poet.song.66000.json','["六街分夜鼓，鄰屋報朝雞。", "寒引秋初老，天將斗轉西。", "滯留聊飲酒，談笑亦分題。", "須信家居樂，休嫌窮巷泥。"]'),
('86801b30-73fa-4c1f-9a1e-2f17581744dd','未試即事雜書率用秋日同文館爲首句  其一','張耒','宋','宋诗','song-poetry','','[]','邃館深魚鑰，華堂靜鎖闈。',48,'全唐诗/poet.song.66000.json','["邃館深魚鑰，華堂靜鎖闈。", "每勞蛩作伴，不與燕同歸。", "古棟蝸成篆，空牆蘚作衣。", "寂寥還泛菊，九日莫相違。"]'),
('b48ea761-6208-43fc-8c21-257f3cc62f8e','未試即事雜書率用秋日同文館爲首句  其二','張耒','宋','宋诗','song-poetry','','[]','名自諸侯選，功收一日長。',48,'全唐诗/poet.song.66000.json','["名自諸侯選，功收一日長。", "文章雜蛟蚓，丹墨有炎凉。", "平昔曾充貢，酸寒未易忘。", "書生成底事，飽死笑東方。"]'),
('8d104149-5e3f-43f9-85e4-bd8e6b98218a','未試即事雜書率用秋日同文館爲首句  其三','張耒','宋','宋诗','song-poetry','','[]','倦枕愁霜苦，晴窗宿霧開。',48,'全唐诗/poet.song.66000.json','["倦枕愁霜苦，晴窗宿霧開。", "幕雲當晝合，袍雪與風來。", "元日彤庭實，春風曲水杯。", "何須戀楊柳，聖世要無媒。"]'),
('268fc7c2-aff1-47f4-b7a6-fb8a5dd41160','詩呈同院後至諸公','張耒','宋','宋诗','song-poetry','','[]','驄馬嘶將近，天門報欲回。',48,'全唐诗/poet.song.66000.json','["驄馬嘶將近，天門報欲回。", "妻孥憐別久，鄰里問歸來。", "左學徒仍在，西城宴許陪。", "腹毛何足問，奇捷看渠魁。"]'),
('7c4f6e3b-eceb-4aaf-84aa-415ce31bb353','初入試院','張耒','宋','宋诗','song-poetry','','[]','莫歎匆匆襆被行，頼逢數子美如英。',64,'全唐诗/poet.song.66000.json','["莫歎匆匆襆被行，頼逢數子美如英。", "已看明月同爲客，應犯初寒復入城。", "白日有書追睡思，青燈無夢聽秋聲。", "直無剔甲逍遙地，幾日疑公太瘦生。"]'),
('acf7e623-fb77-4cd7-bcd3-1998ebeb7ac7','試院即事呈諸公','張耒','宋','宋诗','song-poetry','','[]','天街落日走鳴珂，咫尺衡門不許過。',64,'全唐诗/poet.song.66000.json','["天街落日走鳴珂，咫尺衡門不許過。", "催去據鞍猶鶴望，爭觀夾道已雲羅。", "奏篇定有凌雲賦，招隠今無扣角歌。", "最苦清秋孤美睡，通宵三問夜如何。"]'),
('08f63442-2245-4a3e-95cd-d2370745c2bc','重九考罷試卷書呈同院諸公','張耒','宋','宋诗','song-poetry','','[]','回首登高行復冬，後時只合歎龍鍾。',64,'全唐诗/poet.song.66000.json','["回首登高行復冬，後時只合歎龍鍾。", "愁須白酒來酣戰，詩爲黄花弔不逢。", "十日飛騰過眼疾，萬籤甲乙定誰從。", "共應浄掃氍毹榻，深炷爐香午睡濃。"]'),
('1d7f8dbd-87f9-4359-a1e7-c94b4d2b8090','依韵奉酬慎思兄夜聽誦詩見詠之作','張耒','宋','宋诗','song-poetry','','[]','昔遇晁公淮水東，士衡已聽語如鐘。',64,'全唐诗/poet.song.66000.json','["昔遇晁公淮水東，士衡已聽語如鐘。", "五車講學知無敵，十載論文喜再逢。", "古匣劍光疑鬼泣，夜天虎嘯有風從。", "許侯破的由來事，杜老裁詩曉墨濃。"]'),
('0f9ad6f0-489b-4fa4-9101-1244fa7cc3b4','次韵慎思貽二公誦詩','張耒','宋','宋诗','song-poetry','','[]','西城永夜靈鼉鼓，北寺五更青石鐘。',64,'全唐诗/poet.song.66000.json','["西城永夜靈鼉鼓，北寺五更青石鐘。", "九牧何時官事了，三英聊喜故人逢。", "甲庚定處君無讓，蹀躞歸時我請從。", "欲却睡魔通夕語，明窗茗粥不辭濃。"]'),
('7e38559c-0101-4970-b682-d53bb5ac2880','慎思兄別墅在長沙白鶴山晉陶淡舊居事見本傳今其居有大杉可十數圍蕃茂特異世傳淡藏丹其中用前韵謹賦','張耒','宋','宋诗','song-poetry','','[]','千年騎鶴老仙翁，固是山川秀氣鍾。',64,'全唐诗/poet.song.66000.json','["千年騎鶴老仙翁，固是山川秀氣鍾。", "桃洞自宜無客到，吳門應合有人逢。", "巖前舊隠孤杉老，壺裏真遊白鹿從。", "近有蓬萊讀書客，卜居偶占翠嵐濃。"]'),
('3d4acbc0-98dc-4c27-bc96-ce68971c1e99','嘲无咎夜起明燈聽慎思誦詩','張耒','宋','宋诗','song-poetry','','[]','翠屏香暖秋眠穩，霜冷寶匳金錯刀。',32,'全唐诗/poet.song.66000.json','["翠屏香暖秋眠穩，霜冷寶匳金錯刀。", "誰信苦吟無睡客，挑燈起聽楚人騷。"]'),
('54289736-256d-4fd4-a615-d14abc8a5ae2','再謝周顒之句','張耒','宋','宋诗','song-poetry','','[]','烟飛小玉吳王國，柳暗朱樓鐵甕城。',32,'全唐诗/poet.song.66000.json','["烟飛小玉吳王國，柳暗朱樓鐵甕城。", "見說周顒經案外，亦聞荀粲並床聲。"]'),
('a55d1dbd-66ee-4c91-a0b1-96cd355fcbb9','和慎思與文潜无咎對榻夜話達旦','張耒','宋','宋诗','song-poetry','','[]','燈花昨夜已分明，更聽朝簷喜鵲聲。',32,'全唐诗/poet.song.66000.json','["燈花昨夜已分明，更聽朝簷喜鵲聲。", "明日朱門閉空館，秋風駿馬大梁城。"]'),
('37486534-edd8-40c9-9ab2-bcf9612c9efc','有所歎','張耒','宋','宋诗','song-poetry','','[]','達士不可羈，其次遠羈絆。',96,'全唐诗/poet.song.66000.json','["達士不可羈，其次遠羈絆。", "我無達人風，又不能自遠。", "紛紛隨世俗，碌碌走薄宦。", "其來或遭驅，其去或被挽。", "吾求亦何有，五斗固易辦。", "不師陶淵明，腰爲小兒俯。", "由來爲貧仕，榮辱何敢辯。", "乘田與委吏，孔子不云賤。"]'),
('4469e838-054b-44ee-8874-88d5290121ff','即事二首  其一','張耒','宋','宋诗','song-poetry','','[]','大明海底生，先警我東牖。',96,'全唐诗/poet.song.66000.json','["大明海底生，先警我東牖。", "老人雖未起，曉境默相授。", "山前羣動寂，暗樹語鴉舅。", "昏昏橫水霧，落落欹曉斗。", "厨人已束藴，汲井鳴盎缶。", "沽酒走家奴，理食咨竈婦。", "悠悠春復冬，冉冉昏還晝。", "通塞付大鈞，聊安此微陋。"]'),
('618b15a8-7120-421b-89e9-bbb372c0ed0b','即事二首  其二','張耒','宋','宋诗','song-poetry','','[]','囂塵屏繁務，幽獨會夙心。',72,'全唐诗/poet.song.66000.json','["囂塵屏繁務，幽獨會夙心。", "惟時孟春月，微祿歸園林。", "下有采微逕，上有知時禽。", "終日自嘯歌，寂無鄰里音。", "冉冉溪日下，悠悠山靄陰。", "興闌下絕巘，新月出遙岑。"]'),
('caa4f193-823d-49f3-b0fe-3fe98176dacb','晨起二首  其一','張耒','宋','宋诗','song-poetry','','[]','仲春忽過半，長養候已深。',72,'全唐诗/poet.song.66000.json','["仲春忽過半，長養候已深。", "晨興雨初霽，近目矚平林。", "繁桃張麗錦，好鳥鳴清琴。", "樛枝有新子，翹草無陳心。", "謫官傷局促，端居厭滯淫。", "眷言平生友，乖隔如參辰。"]'),
('e60c9fa0-b45f-4057-829f-10e00d8e07dd','晨起二首  其二','張耒','宋','宋诗','song-poetry','','[]','窮居無遠念，暇日親庖厨。',96,'全唐诗/poet.song.66000.json','["窮居無遠念，暇日親庖厨。", "澤國富滋味，春江出嘉魚。", "鬻市有懸羔，擷園得嘉蔬。", "雖無五鼎烹，薦俎頗有餘。", "導和資一杯，徑使愁肺蘇。", "條味以實氣，聊以彊吾軀。", "聖賢戒求飽，豐德任形臞。", "彼皆勤勵智，我獨懶求愚。"]'),
('bd6cd7f1-a7cf-4c52-a72d-550abae669b4','晨興','張耒','宋','宋诗','song-poetry','','[]','喔喔雞向晨，夙興鄰里靜。',72,'全唐诗/poet.song.66000.json','["喔喔雞向晨，夙興鄰里靜。", "朝光出東崗，秋曉氣耿耿。", "亭亭脫樹葉，寒意已疏勁。", "草根有微露，醲綠尚交映。", "老夫起默坐，覽物感衰盛。", "忽然遇杯酒，酣歌朝達暝。"]'),
('29d5a4af-2147-4a0e-b964-15a7525612c3','朝日','張耒','宋','宋诗','song-poetry','','[]','朝日照山堂，流光泛疏牖。',72,'全唐诗/poet.song.66000.json','["朝日照山堂，流光泛疏牖。", "龍鍾病童子，掃地起持帚。", "堂中空四壁，惟一老病叟。", "蕭條野僧閑，鄙樸老農陋。", "雨來林葉響，霜近蔬甲瘦。", "何以遣幽憂，頼有尊中酒。"]'),
('4b834008-5451-41dc-a5bb-912c1f3b1365','晨起有感','張耒','宋','宋诗','song-poetry','','[]','故歲如曉客，行意不可留。',72,'全唐诗/poet.song.66000.json','["故歲如曉客，行意不可留。", "新春如美人，含笑未舉頭。", "定知當粲然，有待姑少留。", "山川諜光景，梅柳露風流。", "惟有堂中人，一衲暖蒙頭。", "榮枯不到心，萬事良悠悠。"]'),
('83dc97a7-cb7e-4dcf-8c09-3102e2ec61e2','東池','張耒','宋','宋诗','song-poetry','','[]','東池秋水清，歷歷見沙石。',96,'全唐诗/poet.song.66000.json','["東池秋水清，歷歷見沙石。", "枯荷半倒折，風起鳴摵摵。", "悠悠岸邊菊，灼灼好顔色。", "芬芳人不知，寂寞聊自得。", "寒蛩白日啼，晚葉霜餘赤。", "無人野竹繁，積雨平橋側。", "嗈嗈雲間鴻，歲晚霰雪迫。", "乘閒輒獨遊，官閑幸無責。"]'),
('6114fdc0-b36d-4e65-a36a-9ce14c3cd7f6','東溪','張耒','宋','宋诗','song-poetry','','[]','東溪何潺潺，秋水清見底。',96,'全唐诗/poet.song.66000.json','["東溪何潺潺，秋水清見底。", "縱橫小石圓，一一靜無滓。", "空山人不到，漍漍響環佩。", "我來每終日，漱濯弄清泚。", "山居時已久，不省有朝市。", "門闌人客少，跨馬必至此。", "麋鹿見我熟，相對不復起。", "誰知寂寥趣，寄言同聲子。"]'),
('88c9a12d-894e-4db2-a211-cfe19a35c88c','薰風二首  其一','張耒','宋','宋诗','song-poetry','','[]','薰風動嘉樹，日夕成清陰。',72,'全唐诗/poet.song.66000.json','["薰風動嘉樹，日夕成清陰。", "上有枝間鳥，知時爲好音。", "陽春事已往，桃李不可尋。", "頼茲長養功，嘉實薦中林。", "庭虛納凉吹，雲表見遙岑。", "我歌虞氏詩，諧此風中琴。"]'),
('07781708-51d9-41d0-85f0-02792dd7ccc6','薰風二首  其二','張耒','宋','宋诗','song-poetry','','[]','雨霽衆山秀，孤雲散奇姿。',72,'全唐诗/poet.song.66000.json','["雨霽衆山秀，孤雲散奇姿。", "念知朱明始，愛此午景遲。", "居閑敢自逸，隠几玩文詞。", "蕭蕭林風來，亂我書與詩。", "身僻幸無患，官閑詎辭卑。", "逍遙漉酒翁，千載與爲期。"]'),
('20bfd22b-ace5-418a-833b-db48691fb66a','六月五日苦暑','張耒','宋','宋诗','song-poetry','','[]','朱夏忽云季，金流火方燃。',96,'全唐诗/poet.song.66000.json','["朱夏忽云季，金流火方燃。", "遲遲朱輪出，濯濯高雲鮮。", "困翮守茂樾，游魚伏深泉。", "炎炎萬物息，聒耳唯鳴蟬。", "白羽誠么麽，爲功諒徒然。", "那能解煩促，揮肘增勞煩。", "大鈞播一氣，寒暑遞徂遷。", "欲逃既無所，聊此北窗眠。"]'),
('efade018-31b7-4937-aae5-8be6d843fec0','六月八日苦暑二首  其一','張耒','宋','宋诗','song-poetry','','[]','微飆不振髮，皎日沸重淵。',96,'全唐诗/poet.song.66000.json','["微飆不振髮，皎日沸重淵。", "萬木奪華采，祝融方燎原。", "青山瘁無姿，流泉不復寒。", "眷彼道路子，念茲農畝勤。", "荷鋤詎敢後，擔囊無息肩。", "亦知苦可畏，謀食敢遑安。", "三伏方肇序，金融未能完。", "聊安環堵居，酌彼溪中泉。"]'),
('cc7b6158-6513-49d3-9b9c-fe2ac16fd91a','六月八日苦暑二首  其二','張耒','宋','宋诗','song-poetry','','[]','羲和午停車，草木靜若萎。',96,'全唐诗/poet.song.66000.json','["羲和午停車，草木靜若萎。", "我居倦煩促，誰與開我懷。", "出井泉失冷，迎凉幌空開。", "翩翩投林羽，饑渴復誰哀。", "仁哉林間風，爲我時一來。", "惜哉爲功薄，隆赫安能迴。", "觀濤感巨壑，清嘯想高臺。", "徘徊滯心賞，悵望意悠哉。"]'),
('5a11a821-3fcc-4712-9951-8fb6faa14154','秋興三首  其一','張耒','宋','宋诗','song-poetry','','[]','八月禾黍熟，登高望川原。',72,'全唐诗/poet.song.66000.json','["八月禾黍熟，登高望川原。", "山河豁清霽，風日開明鮮。", "晴光散草木，餘爽厲淵泉。", "飄飄孤飛鶻，擊搏無留拳。", "幽獨感摇落，端居驚歲年。", "誰爲知心者，頼有濁醪賢。"]'),
('a7ae767f-2160-4d5f-8c69-3d1ec149292a','秋興三首  其二','張耒','宋','宋诗','song-poetry','','[]','秋日照荆榛，空山莽蕭索。',96,'全唐诗/poet.song.66000.json','["秋日照荆榛，空山莽蕭索。", "人稀雞犬閑，古道轉城脚。", "旗亭數家市，炊烟起籬落。", "牛羊暮求羣，歸烏紛落泊。", "菅麻已在漚，黍稷行可獲。", "歲豐農工勤，膏火通夜作。", "嗟余何爲者，愧與衆同樂。", "南畝亦易謀，咄嗟我力薄。"]'),
('2cab7cb9-6417-46b3-871a-897bb49bc41f','秋興三首  其三','張耒','宋','宋诗','song-poetry','','[]','寒日在東屋，鄰家晚雞啼。',96,'全唐诗/poet.song.66000.json','["寒日在東屋，鄰家晚雞啼。", "闌班黄葉地，白日蟲鳴悲。", "揚揚舊香草，白露彫華姿。", "雖悲就摇落，所喜實離離。", "幽雅敘衣食，備寒戒先期。", "薪芻既收斂，酒醴亦時施。", "嗟我無一廛，薄游倦東西。", "眷言及農畝，歲晚空咨嗟。"]'),
('ce071898-b2c1-46e4-a2bd-51470c7b8278','摇落','張耒','宋','宋诗','song-poetry','','[]','摇落已可悲，况復值秋晏。',120,'全唐诗/poet.song.66000.json','["摇落已可悲，况復值秋晏。", "山深雲物陰，所向皆慘淡。", "疏枝綴陳葉，風至時一散。", "壞壁晝蛩啼，衰草飛蟲戀。", "嗟余守窮谷，秋物已三見。", "胡爲久淹留，不自厭貧賤。", "由來人間事，利害喜相半。", "優游歸隠約，富貴足憂患。", "安行吾不迷，夷路坦可踐。", "保此頑鈍姿，悠哉復誰怨。"]'),
('b7694f79-02bc-4f25-98b5-e67f2c7b79d6','九月一日有作','張耒','宋','宋诗','song-poetry','','[]','怳怳日光薄，蕭蕭風葉吟。',96,'全唐诗/poet.song.66000.json','["怳怳日光薄，蕭蕭風葉吟。", "今辰九月朔，秋物半侵尋。", "頼有堂下菊，芬芳散浮金。", "感茲摇落際，採擷慰孤斟。", "木落見南山，池清照疏林。", "翩翩短羽健，杳杳潜鱗深。", "落漠苦無趣，屢空阻抽簪。", "晴明躡吾屐，晚歲多重陰。"]'),
('500fb059-2f83-4e01-90e2-e2a02cb5830a','觀池漲有作','張耒','宋','宋诗','song-poetry','','[]','清商初用事，力弱殊未完。',72,'全唐诗/poet.song.66000.json','["清商初用事，力弱殊未完。", "假此通夕雨，遂收祝融權。", "平池舊深淺，亦復波浪翻。", "白鷺飛不下，高荷沒青圓。", "是日酒初熟，芳香滿金尊。", "三酌徑就醉，此懷誰與論。"]'),
('a98e1394-a0a7-4285-a558-09e63de98536','七月十日雨炎暑頓解有感','張耒','宋','宋诗','song-poetry','','[]','空山風雨夕，微雨凄房櫳。',72,'全唐诗/poet.song.66000.json','["空山風雨夕，微雨凄房櫳。", "徂年兆摇落，感歎白頭翁。", "謫居困炊玉，無田願年豐。", "欲持一杯酒，旁舍慶老農。", "烈日辭紈扇，高林墜晚風。", "青燈夜齋靜，不睡獨聞蛩。"]'),
('e2d83416-e744-4108-8a3e-6a3dd4121308','出伏調潘十','張耒','宋','宋诗','song-poetry','','[]','伏盡熱隨盡，古語常有憑。',96,'全唐诗/poet.song.66000.json','["伏盡熱隨盡，古語常有憑。", "淮南歲苦旱，秋暑鬰方蒸。", "老火熾而燄，弱金融未凝。", "火雲大江沸，烈日羣山赬。", "平生白羽扇，揮拂何功能。", "蓬頭卧永晝，起冠汗沾纓。", "柯山屢空子，貧病復相仍。", "衡茅未可詣，作詩問寢興。"]'),
('7a06dd13-fbdb-487d-90da-6fa0eedd7483','九月下旬有作二首  其一','張耒','宋','宋诗','song-poetry','','[]','今辰九月末，秋物能幾許。',72,'全唐诗/poet.song.66000.json','["今辰九月末，秋物能幾許。", "翩翩風中葉，卷卷自飛舞。", "餘姿不復妍，日夜逐塵土。", "寥寥空枝高，但有寒鳥聚。", "天時不汝留，變化竟誰主。", "今古無奈何，悲歌徒自苦。"]'),
('f6bc9f44-fa56-4cd1-9adc-bd5694b0a659','九月下旬有作二首  其二','張耒','宋','宋诗','song-poetry','','[]','慘慘歲云暮，寒日無停光。',72,'全唐诗/poet.song.66000.json','["慘慘歲云暮，寒日無停光。", "況復陰晦多，景短重雲長。", "梳頭坐清曉，朝飯熟黄粱。", "官閑無事業，終日偃空堂。", "經時不跨馬，門徑秋蕪荒。", "惟有霜後山，當簾對蒼蒼。"]'),
('1dbd4af9-13cc-4dcb-9a29-ba40dc39a5c1','白月','張耒','宋','宋诗','song-poetry','','[]','白月照世界，山河受清光。',72,'全唐诗/poet.song.66000.json','["白月照世界，山河受清光。", "豈獨耳目清，瑩洗肝膈凉。", "中夜掃寬虛，仰得天一方。", "湛碧磨青銅，精金點星芒。", "我心方無思，偃息在高堂。", "慎勿憂世故，彼昏謂汝狂。"]'),
('6b0dc3e0-7881-4f3a-bf24-4616172276aa','初晴對月','張耒','宋','宋诗','song-poetry','','[]','平生愛明月，豈以解煩燠。',72,'全唐诗/poet.song.66000.json','["平生愛明月，豈以解煩燠。", "及茲霜夜對，任使體生粟。", "冰天凝紺冷，氛祲避不觸。", "煌煌七金徽，但掛寒斗曲。", "蕭蕭瞀栖葉，悄悄鼾眠屋。", "三更清到骨，亂以杯中綠。"]'),
('d634d198-1801-4cab-aa19-71f281bec44b','雨中晨起','張耒','宋','宋诗','song-poetry','','[]','端居多滯念，秋至一蕭散。',72,'全唐诗/poet.song.66000.json','["端居多滯念，秋至一蕭散。", "况茲炎凉異，微冷風雨旦。", "空山陰靄積，槭槭木聲變。", "絺衣感輕單，素褐催補綻。", "泥行苦長鬚，買酒不可緩。", "洗盞自迎門，一杯聊自勸。"]'),
('bf2b76a2-17bf-43f3-95b6-b3604ba1cacb','苦雨','張耒','宋','宋诗','song-poetry','','[]','春淺天尚寒，雨多聲入夜。',72,'全唐诗/poet.song.66000.json','["春淺天尚寒，雨多聲入夜。", "幽人不出門，坐惜梅花謝。", "庭竹未抽萌，酴醾將覆架。", "芳時喜病愈，淺酌供情話。", "趨世劇曳牛，投閒如啖蔗。", "因逢老農談，悔不初學稼。"]'),
('4ce68219-b4ca-40e2-bd78-5bcbd7b95311','雨霽','張耒','宋','宋诗','song-poetry','','[]','滯雨忽雲霽，園林有清暉。',72,'全唐诗/poet.song.66000.json','["滯雨忽雲霽，園林有清暉。", "時鳥亦和鳴，好風清且微。", "遠愧深山僧，趺坐掩禪扉。", "豈知芳非歇，詎傷寒暑違。", "一念與道寂，九旬淡無爲。", "躡心探斯理，吾今其庶幾。"]'),
('0eb86831-6eb6-45d9-a9d0-526b58124e73','賀雨拜表','張耒','宋','宋诗','song-poetry','','[]','羣雲雨事畢，振旅不復陣。',72,'全唐诗/poet.song.66000.json','["羣雲雨事畢，振旅不復陣。", "掃天無一塵，千里還綠潤。", "晨朝大明賀，沙路萬蹄印。", "朝光泛翠瓦，佳氣去人近。", "頗避斧扆尊，侑膳飯龍筍。", "願君愛物心，從此至堯舜。"]'),
('676c8af6-7f31-4cb5-829d-fd6ee38437cc','春雨','張耒','宋','宋诗','song-poetry','','[]','南山多夕陰，夜雨復達旦。',120,'全唐诗/poet.song.66000.json','["南山多夕陰，夜雨復達旦。", "瀟瀟晚未已，零落雲物亂。", "陰沉晝生寒，閉戶守餘炭。", "官庭草木合，山吏午已散。", "悠悠對朝景，念此春已半。", "昨日櫻桃花，紛紛落如霰。", "天時不可駐，今古一嗟嘆。", "唯應痛行樂，此計乃最善。", "簪紳束我體，局促困游宦。", "何當有茅屋，放意行所願。"]'),
('6d0de993-4617-4e14-9830-01a9dbae5674','春雨','張耒','宋','宋诗','song-poetry','','[]','春雨不肯晴，春雲與地平。',148,'全唐诗/poet.song.66000.json','["春雨不肯晴，春雲與地平。", "柯山數椽屋，晝夜傾簷聲。", "陰沉人意惡，但願醉不醒。", "園花知在亡，渠溜飄紅英。", "今年窮到骨，憔悴客江城。", "花時不得出，風雨掩柴荆。", "自我學道來，萬事一羽輕。", "惟有惜春意，未忘兒女情。", "齟齬可奈何，努力飽飯行。", "往日雖莫挽，來日豈無程。", "忽記祖燕公，佳句與帝賡。", "今歲隨宜過寒食，明年倍調作清明。"]'),
('c758507a-7c73-49da-94c1-005f3ef87b7a','喜雨止','張耒','宋','宋诗','song-poetry','','[]','敬亭與吾期，今日雨當止。',96,'全唐诗/poet.song.66000.json','["敬亭與吾期，今日雨當止。", "靜掃峰頭雲，秀色粲如喜。", "我慚無以酢，園逕欣細履。", "夜來四簷聲，添我北池水。", "破圩久不補，積潦嚙其址。", "南人麥禾薄，稻壠魚尾尾。", "豐穰未敢望，疲餓何由起。", "飽食但高眠，自慚稱刺史。"]'),
('f532e70b-c1f7-4718-bc19-76735b519141','仲春苦雨','張耒','宋','宋诗','song-poetry','','[]','仲春乃積雨，和景良未舒。',96,'全唐诗/poet.song.66000.json','["仲春乃積雨，和景良未舒。", "園林阻幽步，塊坐守溫爐。", "中庭下水鳥，隙地長寒蕪。", "流紅委花外，渟碧漲池餘。", "商羊未悔禍，椒醑屢傳巫。", "豈惟政無補，多慚誠未孚。", "農事滯南畝，土功隳敗圩。", "悠哉欲何奈，濁酒且爲娛。"]'),
('5183cba6-6686-432e-abc1-f26e8c34d3e8','苦雨','張耒','宋','宋诗','song-poetry','','[]','重雲冒山椒，大江浸其麓。',96,'全唐诗/poet.song.66000.json','["重雲冒山椒，大江浸其麓。", "通爲一沮洳，哀此塗泥渥。", "居寄佛殺山，舉趾厭局促。", "餘飄污巾几，積潤繁篁竹。", "門前耕野靜，時得舒倦目。", "美哉百畝稻，整整照人綠。", "深蕪下白鳥，霽嶺明秀木。", "感此歌豐年，卒歲期飽腹。"]'),
('64254af1-771a-4d8d-ab2d-aae4d525b7ea','苦雨','張耒','宋','宋诗','song-poetry','','[]','伏盡暑初變，西風作秋聲。',120,'全唐诗/poet.song.66000.json','["伏盡暑初變，西風作秋聲。", "瀟瀟晚雨急，達旦聲不停。", "陰暝雞失警，微凉肅晨興。", "湍流昌階闥，積潦被門庭。", "仰視天蓋低，玄雲送驚霆。", "黑蜧樂以逞，商羊方未寧。", "后土何茫茫，流潦浩縱橫。", "憂念在民食，敢私蘭菊榮。", "漠漠暮未已，琅琅夜還增。", "嗟余但高枕，飽食愧疲氓。"]'),
('e3d63fb9-72f7-4d36-928c-23e4e1c29dbf','春旱二首  其一','張耒','宋','宋诗','song-poetry','','[]','大野拱連山，晴空轉規日。',72,'全唐诗/poet.song.66000.json','["大野拱連山，晴空轉規日。", "青春散坱莽，積水中蕩潏。", "欣欣見羣動，咄咄爭湧出。", "滯留無好懷，風景獨蕭瑟。", "離羣與誰語，塊坐守蓬蓽。", "巵酒樂餘春，沉憂畏生疾。"]'),
('50b8f4f2-4883-400d-ab04-b5bad1dd3dc5','春旱二首  其二','張耒','宋','宋诗','song-poetry','','[]','風雲閑益高，旱色起諸嶺。',72,'全唐诗/poet.song.66000.json','["風雲閑益高，旱色起諸嶺。", "施生澤未渥，曉氣挾餘冷。", "飛沙磣桃李，碧草思耿耿。", "麥根不走地，稻壠卧陳梗。", "蛟龍且偷安，雷電勢欲逞。", "憫農非我事，剛復念閭井。"]'),
('6922e04b-f572-4c1f-8cb7-e64bb9487547','春雨','張耒','宋','宋诗','song-poetry','','[]','浪浪簷前雨，晝夜來不極。',120,'全唐诗/poet.song.66000.json','["浪浪簷前雨，晝夜來不極。", "青苔生空廊，蝸涎被四壁。", "出門無所往，端居守籠翮。", "鳴呼林中鳩，聒聒方自得。", "林花掃餘姿，高柳沐佳色。", "悠悠三月殘，春物行欲息。", "感之欲何奈，取醉遣朝夕。", "穿泥得新筍，紫籜裹新白。", "從容婦子語，草草田野食。", "明日還復然，慵頑已成癖。"]'),
('c4419603-abb2-4091-a3a5-f302f38cb3f8','春旱初雨','張耒','宋','宋诗','song-poetry','','[]','春泥不沾犁，四月若三伏。',120,'全唐诗/poet.song.66000.json','["春泥不沾犁，四月若三伏。", "哀哉麥無秀，父子壠頭哭。", "誰驚耽眠龍，霹靂震萬屋。", "從空倒江海，焦槁快一浴。", "終然霽威怒，飄颯斷還續。", "晚陰凉觀闕，夜響起松竹。", "後時悲夏穫，入土喜秋穀。", "聊爲目前慰，未敢信果腹。", "豐凶繫□詳，望歲走牲玉。", "我無憂民責，理此杞與菊。"]'),
('2708d1d1-0cb0-4de7-a064-37b04df8660a','庭菊','張耒','宋','宋诗','song-poetry','','[]','窮秋慘無姿，向榮盡枯槁。',96,'全唐诗/poet.song.66000.json','["窮秋慘無姿，向榮盡枯槁。", "可憐中庭菊，灼灼顔色好。", "豈無風霜苦，所守良自保。", "清商振驅除，爾獨傲百草。", "煌煌中央色，嚴麗謝浮姣。", "山家有薄酒，爲爾數傾倒。", "嘗聞仙人術，採餌庶難老。", "呼童掃藥齋，遲爾寒英擣。"]'),
('847c499d-d8fa-4b0a-8a42-4e7211c79b66','次韵蘇翰林送黄師是赴兩浙','張耒','宋','宋诗','song-poetry','','[]','昔見君納婦，今見君抱孫。',108,'全唐诗/poet.song.66000.json','["昔見君納婦，今見君抱孫。", "先公力種德，子合大其門。", "何爲亦如我，有抱不得言。", "崢嶸胸中氣，默默自吐吞。", "誰如東坡老，感激論元元。", "欲將洛陽裘，盡蓋江湖村。", "既係海若頸，又鞭江胥魂。", "意令仰天民，不隔頂上盆。", "我獨乞禪床，一氣中夜存。"]'),
('95486f54-a4f8-4170-a092-e5f535faf46f','次韵子夷兄弟十首  其一','張耒','宋','宋诗','song-poetry','','[]','暑雨衆物成，園林粲垂實。',48,'全唐诗/poet.song.66000.json','["暑雨衆物成，園林粲垂實。", "官閒縻歲月，裨補百無一。", "委身作書蠹，檢性就僧律。", "古味雖未亡，塵埃滿琴瑟。"]'),
('d04e6ddc-ddd5-4f6f-84a2-90d46e10525b','次韵子夷兄弟十首  其二','張耒','宋','宋诗','song-poetry','','[]','金馬聊代耕，淺郎亦爲官。',48,'全唐诗/poet.song.66000.json','["金馬聊代耕，淺郎亦爲官。", "何必歌五噫，遭非如伯鸞。", "物生各自遂，蕭艾與芝蘭。", "詩人亦多事，屑屑計鶉貆。"]'),
('33df2d10-2a86-49da-9cfe-522ea0e56b6d','次韵子夷兄弟十首  其三','張耒','宋','宋诗','song-poetry','','[]','愔愔坐歲晏，忽枉故人書。',48,'全唐诗/poet.song.66000.json','["愔愔坐歲晏，忽枉故人書。", "頗說清淮濱，卜築有幽居。", "歸興浩滿懷，端如果投狙。", "功名繫遇合，不遇欲何如。"]'),
('65688ff1-4d0f-4442-8d50-713367b965df','次韵子夷兄弟十首  其四','張耒','宋','宋诗','song-poetry','','[]','出門復入門，愧此櫪上馬。',48,'全唐诗/poet.song.66000.json','["出門復入門，愧此櫪上馬。", "壯心磨不盡，撫劍還悲咤。", "感時高歌放，泣古幽淚洒。", "端憂蹇無成，駕言我心寫。"]'),
('1d9c3d2e-9695-418a-8d08-a52cd3cfe334','次韵子夷兄弟十首  其五','張耒','宋','宋诗','song-poetry','','[]','少年初入路，見謂醒日少。',48,'全唐诗/poet.song.66000.json','["少年初入路，見謂醒日少。", "春風牡丹市，走馬帽簷倒。", "知音君伯仲，騏驥與腰褭。", "五年復相逢，但怪酒盞小。"]'),
('2ad2daff-d6bb-4a08-97df-1ead2ea3e86e','次韵子夷兄弟十首  其六','張耒','宋','宋诗','song-poetry','','[]','經時不飲酒，廩薄人口衆。',48,'全唐诗/poet.song.66000.json','["經時不飲酒，廩薄人口衆。", "人閒多是非，不敢盜鄰甕。", "二公洛陽日，想見飲屢痛。", "行求放湖海，種秫代官俸。"]'),
('552ec2d9-f116-44a7-96ff-a8f3dc9639f0','次韵子夷兄弟十首  其七','張耒','宋','宋诗','song-poetry','','[]','閒官冷於水，塊坐守編簡。',48,'全唐诗/poet.song.66000.json','["閒官冷於水，塊坐守編簡。", "時無蘇司業，何處見酒盞。", "新凉枕簟瑩，付睡與雙眼。", "念我南山苗，經年廢鋤鏟。"]'),
('92fd0bea-6713-4f1d-9dd4-326fc3186a02','次韵子夷兄弟十首  其八','張耒','宋','宋诗','song-poetry','','[]','文園得武皇，引疾常避事。',48,'全唐诗/poet.song.66000.json','["文園得武皇，引疾常避事。", "佳哉意殊深，遺迹邈不嗣。", "揚公漫投閣，不禁問奇字。", "致身毀譽外，乃得免疑似。"]'),
('c114e813-889e-4203-b7e2-0a6808a9f592','次韵子夷兄弟十首  其九','張耒','宋','宋诗','song-poetry','','[]','呦呦中林鹿，那得伏鞍銜。',48,'全唐诗/poet.song.66000.json','["呦呦中林鹿，那得伏鞍銜。", "愧我蕨薇姿，塵埃敝朝衫。", "山人不歸山，頗被猿鶴讒。", "欲追甫白遊，千古感至諴。"]'),
('57809109-1a48-4f03-ae27-ea43a5a4ab9d','次韵子夷兄弟十首  其一○','張耒','宋','宋诗','song-poetry','','[]','昔有獨醒士，絕口避醁醽。',48,'全唐诗/poet.song.66000.json','["昔有獨醒士，絕口避醁醽。", "折楊得衆笑，無地至秦青。", "周詩念忠嘉，所貴食野苹。", "良時不可再，佳人難合并。"]'),
('be2112cc-92ca-490f-aea3-15959c9a3475','喜吉老甥見過','張耒','宋','宋诗','song-poetry','','[]','西風吹藜藿，秋色滿環堵。',168,'全唐诗/poet.song.66000.json','["西風吹藜藿，秋色滿環堵。", "悲蟲語窗月，陰蕊開夕露。", "門閑賓客少，鳥雀任散聚。", "楊甥時過我，論詩朝達暮。", "新茶磨細雪，甘井漱清乳。", "匆匆貧家飯，藜藿不滿俎。", "頗言行有日，征艎下洛渚。", "喜汝將鳳歸，驚余髮加素。", "老慵愁應接，兒女較口語。", "樂逢親骨肉，情話到爾汝。", "先君外孫子，惟爾冠俁俁。", "平生女䇓兄，宜爾有風矩。", "長安木葉落，雨送萬家暑。", "凉風當沽酒，爲我醉起舞。"]'),
('daa0fa26-c541-41ed-9c27-9d7ee49db270','劉伯壽秘校','張耒','宋','宋诗','song-poetry','','[]','將軍卷金甲，獨卧嵩山阿。',240,'全唐诗/poet.song.66000.json','["將軍卷金甲，獨卧嵩山阿。", "千金買蛾眉，晝夜飲且歌。", "時平武庫鎖，賂買戎狄和。", "不復用英雄，惜哉雙鬢皤。", "延我寒夜歡，清尊不辭多。", "壯氣老未已，醉來鬚屢摩。", "充國年七十，立功未蹉跎。", "我欲勸公起，拂塵揮舊戈。", "公言一世中，歡樂能幾何。", "安用身外名，功高竟消磨。", "家住太室陽，開門對嵯峨。", "嘉肴薦尊俎，有酒如江河。", "度曲得新聲，詞成自吟哦。", "樂此常不足，尚安知其他。", "我愕不知答，高賢固殊科。", "馬援喜功名，旅死遭譏訶。", "陶潜雖放情，但爲碩人薖。", "公於二者間，安處行逶迤。", "寒廳有修竹，野泉漲微波。", "不厭徒馭勤，高車幸來過。"]'),
('0e6143f0-c51c-45ed-9ff9-cfbc9e4f4bf7','送梅子明通判餘杭','張耒','宋','宋诗','song-poetry','','[]','東南山水窟，錢塘吳越都。',96,'全唐诗/poet.song.66000.json','["東南山水窟，錢塘吳越都。", "吾人神仙後，厭直承明廬。", "一舸去莫挽，落帆風月湖。", "蹁躚青衿子，能誦先生書。", "借問太守誰，子雲蜀名儒。", "家有王陽金，清商奏簫竽。", "相逢不妨飲，坐嘯治有餘。", "遙知子還日，未厭浙江魚。"]'),
('f1b151cc-1f3b-4d39-b832-235e17e63199','送呂安禮','張耒','宋','宋诗','song-poetry','','[]','呂子有奇氣，少年事詩書。',216,'全唐诗/poet.song.66000.json','["呂子有奇氣，少年事詩書。", "不肯衣逢掖，而隨市井儒。", "白紵霜雪袍，朱纓貫金殳。", "大醉必走馬，長呼挽雕弧。", "興罷有餘歡，清歌倚簫竽。", "春風動狂思，夜席擁妖姝。", "羣兒傍笑之，謂子脫撿拘。", "而我獨知子，壯茲真丈夫。", "屑屑五斗米，其重無錙銖。", "何爲愛瑣屑，妄自苦其軀。", "子亦愛我拙，相逢每躊躇。", "論詩夜齋靜，秀氣出璠璵。", "遠官無與歡，見君心獨娛。", "如何忽告別，决去如驚鳬。", "矯矯黄鵠姿，枳棘非所居。", "清明擇士日，子豈久泥塗。", "送別動苦懷，乖離感羈孤。", "搔首歲暮天，詩成悲有餘。"]'),
('0c0f648f-d531-4b60-b94e-b21485b8767b','呂尉醉中索詩爲別','張耒','宋','宋诗','song-poetry','','[]','吾友呂子者，其人藝且文。',144,'全唐诗/poet.song.66000.json','["吾友呂子者，其人藝且文。", "何侯綠沉鎗，顔皋弓六鈞。", "勿謂豪少年，詩書精討論。", "文詞踵騷雅，豈但驚庸人。", "羣兒事膏沐，炫粥倚市門。", "汲汲恐不售，惟憂貨非珍。", "子獨抱奇璞，九襲包衣巾。", "塵埃自蒙垢，但畏人知聞。", "區區事邊幅，碌碌隨俗塵。", "顧我未免此，深慚非子倫。", "離別可奈何，高歌倒清尊。", "願子重輝光，去去翔青雲。"]'),
('e5368a77-f273-4ea4-9370-d59e3518b47c','送陳器之','張耒','宋','宋诗','song-poetry','','[]','投身落窮谷，默默類囚拘。',288,'全唐诗/poet.song.66000.json','["投身落窮谷，默默類囚拘。", "情忘侶木石，機謝友禽魚。", "粲粲陳夫子，文章德行俱。", "雖云相知晚，既合乃不渝。", "我官洛水濱，君寄鹿山隅。", "孰謂百里遙，滿案堆君書。", "詩壇兩不懾，日夕鬭戈殳。", "我贈白玉璧，子還明月珠。", "今春子遇我，爲我駐驪駒。", "高懷坐披豁，一飲倒雙壺。", "聯騎失洛橋，據鞍遞歌呼。", "劇談燼飲燭，痛飲銷炎爐。", "首夏餘春妍，子還自西都。", "連朝守杯勺，芍藥正芬敷。", "插花烏帽傾，醉倒傍人扶。", "已別尚反顧，將歸重躊躇。", "官期子當滿，念別久鬰紆。", "况乃西郊道，匆匆遇行車。", "一酌不暇勸，矧欲盡子娛。", "亦知微誠薄，所惜違區區。", "親友義不小，况乃知心歟。", "忽忽流水濱，尚將執子袪。", "願子保多福，六翮縱南圖。", "永此金石交，皦皦堅終初。"]'),
('532d7145-49cd-4f1e-9ddb-f4679acbf9a1','別外甥楊克一','張耒','宋','宋诗','song-poetry','','[]','彈琴不須弦，意在宮徵外。',72,'全唐诗/poet.song.66000.json','["彈琴不須弦，意在宮徵外。", "濁醪分美惡，於道猶蒂芥。", "平生分別盡，獨此有涇渭。", "坐令劉石徒，笑我猶嗜味。", "秋風三十里，碧鱖兼紫蟹。", "參軍呼可應，肯使空樽對。"]'),
('58b73f97-b4d5-4760-a260-b235166dbc4c','感遇二十五首  其一','張耒','宋','宋诗','song-poetry','','[]','幽居念世務，頗復窺造物。',72,'全唐诗/poet.song.66000.json','["幽居念世務，頗復窺造物。", "通爲一憒憒，愚智更出沒。", "漏天呀不補，淫雨方蕩潏。", "豈獨無良苗，稂莠亦飄忽。", "惟餘尊中物，三酌便兀兀。", "此事頗有憑，時從散幽鬰。"]'),
('6376e523-2a8c-4f99-802c-829acb94d605','感遇二十五首  其二','張耒','宋','宋诗','song-poetry','','[]','毀竹伐梧桐，意欲困鳳凰。',72,'全唐诗/poet.song.66000.json','["毀竹伐梧桐，意欲困鳳凰。", "彼雖無食息，逸氣自高翔。", "鳳何求於人，人自欲鳴岡。", "麾之亦安有，庚子鴞在堂。", "昂昂青雲士，忍饑而擇糧。", "使果腹是求，何憂無五漿。"]'),
('97717a3c-fc1d-4156-808f-433267de5287','感遇二十五首  其三','張耒','宋','宋诗','song-poetry','','[]','士生有輕重，初非他人爲。',108,'全唐诗/poet.song.66000.json','["士生有輕重，初非他人爲。", "視身真千鈞，所壓無不摧。", "羣偷讓弊漢，喘走恐後時。", "隆中賢少年，長嘯弄鋤犁。", "白頭左將軍，斂衽喜得時。", "狠石挈紫髯，老瞞受鞭笞。", "艱難永安詔，委國忘其兒。", "心知龍鸞人，不顧鴟鴉資。", "使無三顧重，一飽起相疑。"]'),
('22448319-1381-47d0-9ca0-36e1689d5636','感遇二十五首  其四','張耒','宋','宋诗','song-poetry','','[]','世無英霸器，俚叟誦詩書。',96,'全唐诗/poet.song.66000.json','["世無英霸器，俚叟誦詩書。", "不能靜丘民，安用稱唐虞。", "堂堂贊皇公，龍變誰可拘。", "邂逅逢可人，奮身爲謀謨。", "草書救深州，元翼終就屠。", "誰能叱邸吏，姦將立改圖。", "天方去大和，拔公去其都。", "十年奇才論，獨智羞羣愚。"]'),
('40aa7cb8-7514-4cca-8aa8-670eaea0e542','感遇二十五首  其五','張耒','宋','宋诗','song-poetry','','[]','秋房燈火靜，客睡亦復安。',96,'全唐诗/poet.song.66000.json','["秋房燈火靜，客睡亦復安。", "弭彊力汲汲，涉廣心漫漫。", "白露下百草，心知歲將闌。", "彼微者啼鴂，職使仇蕙蘭。", "吾非蒿目人，初不與世患。", "淫雨作橫流，執蠡挹之乾。", "我師青牛書，不爭忌處先。", "既自守吾寶，在辱亦何歎。"]'),
('8d30fd31-cf3a-400e-9682-a1d9215bbc10','感遇二十五首  其六','張耒','宋','宋诗','song-poetry','','[]','羣動同大塊，冥冥含至精。',48,'全唐诗/poet.song.66000.json','["羣動同大塊，冥冥含至精。", "乾坤職覆載，日月互昏明。", "蚊蟲共一器，擾擾一時爭。", "推移付大化，終古一空名。"]'),
('fe2116d3-2d81-48a8-b5a2-b4387776ece0','感遇二十五首  其七','張耒','宋','宋诗','song-poetry','','[]','太冬積嚴殺，布令兆微霜。',48,'全唐诗/poet.song.66000.json','["太冬積嚴殺，布令兆微霜。", "淒淒中園木，華采欻摧藏。", "豈無孤芳者，佳菊獨煌煌。", "後彫雖爾德，曷補蕙蘭傷。"]'),
('6ff9387a-0db3-4232-bf59-83c51e178edc','感遇二十五首  其八','張耒','宋','宋诗','song-poetry','','[]','炎劉運欲圮，蠹孽依根生。',48,'全唐诗/poet.song.66000.json','["炎劉運欲圮，蠹孽依根生。", "姦臣助斲喪，主意不得行。", "云誰知巢穴，請劍有朱卿。", "傷哉滔天禍，成此直士名。"]'),
('240a65ed-6979-4e71-836a-018fa50fbcee','感遇二十五首  其九','張耒','宋','宋诗','song-poetry','','[]','唐皇欲喪亂，豺虎依山丘。',48,'全唐诗/poet.song.66000.json','["唐皇欲喪亂，豺虎依山丘。", "君王信李訓，玉殿行戈矛。", "繫狗不係首，遭噬血橫流。", "堂堂贊皇公，委棄不與謀。"]'),
('2432f388-cc82-4063-b923-f1a3416395bc','感遇二十五首  其一○','張耒','宋','宋诗','song-poetry','','[]','腹心主包藏，爪齒以自衛。',60,'全唐诗/poet.song.66000.json','["腹心主包藏，爪齒以自衛。", "折衝須豪英，靖國用君子。", "遐哉三五朝，此道無不備。", "晏嬰才愧管，齊景不霸世。", "商子德慚奚，秦彊仍早圮。"]'),
('6961ae1d-e8b8-44af-81d2-17f3fcd3d76e','感遇二十五首  其一一','張耒','宋','宋诗','song-poetry','','[]','風霜凜已高，歲月逝云邁。',48,'全唐诗/poet.song.66000.json','["風霜凜已高，歲月逝云邁。", "蕭條陋巷士，藜藿守耿介。", "欲吐胸中語，旁人笑言大。", "漆室非近憂，宜遭鄰里怪。"]'),
('07d9fb37-1fe6-44a0-84ea-76d93add2dc7','感遇二十五首  其一二','張耒','宋','宋诗','song-poetry','','[]','登高望海縣，秋日麗玉京。',72,'全唐诗/poet.song.66000.json','["登高望海縣，秋日麗玉京。", "喧闐車馬音，風震入青冥。", "大明屬昌運，戴白不知兵。", "華衣美酒食，婦織子孫耕。", "生無係虜憂，乃覺患禍輕。", "請看五季世，戰地猶榛荆。"]'),
('cc8b8bee-ee51-43c9-9444-252639118502','感遇二十五首  其一三','張耒','宋','宋诗','song-poetry','','[]','西京全盛日，宮闕上參天。',84,'全唐诗/poet.song.66000.json','["西京全盛日，宮闕上參天。", "建章千萬戶，白晝下神仙。", "金瓊麗雲日，栱角壓山川。", "一朝喪亂至，兩觀入戈鋋。", "漸臺既已平，長門隨飛烟。", "物大變亦巨，安榮竟徂遷。", "毋怪秦漢君，甘心惑神仙。"]'),
('a83e9f70-fb66-4a17-89be-c35ddb5ec7b5','感遇二十五首  其一四','張耒','宋','宋诗','song-poetry','','[]','穰侯抵關中，頗畏諸侯客。',72,'全唐诗/poet.song.66000.json','["穰侯抵關中，頗畏諸侯客。", "搜車計已遲，終困范公策。", "庸夫吝富貴，百計私自惜。", "勢移禍敗至，智巧竟何益。", "至公覽英俊，苴補乃無隙。", "請看桑林餓，亦脫趙子厄。"]'),
('a008aa84-90d4-4a5a-b33b-60c746cff0f0','感遇二十五首  其一五','張耒','宋','宋诗','song-poetry','','[]','釁隙不在大，巫臣圖夏姬。',48,'全唐诗/poet.song.66000.json','["釁隙不在大，巫臣圖夏姬。", "百端終困楚，吳子會黄池。", "怨有大於此，居高易逢危。", "何言戒困獸，無易簀中尸。"]'),
('dc0e629d-b0e1-40ab-b4e9-961b0fab857e','感遇二十五首  其一六','張耒','宋','宋诗','song-poetry','','[]','林居屏百患，覃思觀幽遐。',60,'全唐诗/poet.song.66000.json','["林居屏百患，覃思觀幽遐。", "炎黄已蕪沒，末路多玼瑕。", "私智互馳騁，短長迭矜夸。", "更相爲禍福，勝負時紛拏。", "超然赤松子，高笑在雲霞。"]'),
('5936c48f-ec8b-4bef-bec1-69070fea5d45','感遇二十五首  其一七','張耒','宋','宋诗','song-poetry','','[]','周王仗黄鉞，自謂將天威。',84,'全唐诗/poet.song.66000.json','["周王仗黄鉞，自謂將天威。", "孤竹兩君子，采薇旁笑之。", "豈徒驚世俗，趨死乃如歸。", "周衰楚蒙吏，快辯多文詞。", "高言毀二子，至與盜跖齊。", "夷齊固齊聖，於道豈無知。", "輕身立世教，爭奪尚如斯。"]'),
('fc964a9f-b81c-4bd9-a6d6-5ad7407cb37e','感遇二十五首  其一八','張耒','宋','宋诗','song-poetry','','[]','江湖有潜鱗，頗厭沮澤陋。',72,'全唐诗/poet.song.66000.json','["江湖有潜鱗，頗厭沮澤陋。", "朅來游滄溟，矯首觀宇宙。", "是時三神山，忽隕巨鰲首。", "奔波走仙聖，龍蜃紛格鬭。", "重淵沸日月，萬類錯昏晝。", "掉尾歸去來，蓮巢以爲友。"]'),
('c693a96a-578b-4769-9ffc-bdcf0d922a08','感遇二十五首  其一九','張耒','宋','宋诗','song-poetry','','[]','衆聖演世教，金仙獨圓成。',48,'全唐诗/poet.song.66000.json','["衆聖演世教，金仙獨圓成。", "徒緣異形範，乃復遭譏評。", "幽居覽物化，且復究吾形。", "捐書守寂寞，萬化歸無生。"]'),
('0cab30a6-a38d-4beb-a843-2e1b919ee861','感遇二十五首  其二○','張耒','宋','宋诗','song-poetry','','[]','治疾弭靈藥，爽然疾有瘳。',48,'全唐诗/poet.song.66000.json','["治疾弭靈藥，爽然疾有瘳。", "因茲涉方書，仙聖或可求。", "豈疾乃可治，而生不可留。", "吾將飛五金，息駕於蓬丘。"]'),
('409d2993-b098-4288-8c33-3e65410c8c6b','感遇二十五首  其二一','張耒','宋','宋诗','song-poetry','','[]','懷王棄屈子，憔悴楚江湄。',96,'全唐诗/poet.song.66000.json','["懷王棄屈子，憔悴楚江湄。", "終然葬魚腹，終古耀文詞。", "千年洛陽客，作賦不無譏。", "謂當棄之去，覽德乃下之。", "君臣本大倫，當以恩義持。", "如皆輕合散，是與塗人夷。", "靈均豈願沉，深意實在茲。", "傅懷終泣死，何亦拳拳爲。"]'),
('1b84aeb0-cc4c-4def-9203-34a8a27f724e','感遇二十五首  其二二','張耒','宋','宋诗','song-poetry','','[]','微陰兆九地，萬木方滋榮。',72,'全唐诗/poet.song.66000.json','["微陰兆九地，萬木方滋榮。", "微霜初可履，回首陽泉冰。", "秦王按劍日，豐沛赤精生。", "光輝能幾時，日中月已升。", "達人知其然，居世忘驕矜。", "彼哉夸毗子，志氣易滿盈。"]'),
('6b100c4a-61de-45d4-a2d4-c4fe6f214702','感遇二十五首  其二三','張耒','宋','宋诗','song-poetry','','[]','處世三不遇，放歌歸去來。',48,'全唐诗/poet.song.66000.json','["處世三不遇，放歌歸去來。", "林卧觀太初，悠悠付一杯。", "扶摇震雲海，三山安在哉。", "金丹或可學，他日出塵埃。"]'),
('b3c758ce-bc85-43fd-9208-2cc06506f90e','感遇二十五首  其二四','張耒','宋','宋诗','song-poetry','','[]','蒼鷹初化鳩，未忍望擊搏。',72,'全唐诗/poet.song.66000.json','["蒼鷹初化鳩，未忍望擊搏。", "照水或見形，乃見悔其昨。", "麗戎有奇女，遭虜常涕洟。", "改服登晉宮，更恨來苦遲。", "變化驅念慮，丈夫或有之。", "貧賤矜懷寶，富貴乃無奇。"]'),
('4ac28c21-8a9c-4ce0-9463-cd79b03a3ad4','感遇二十五首  其二五','張耒','宋','宋诗','song-poetry','','[]','繅絲未緣魚，有絲生網心。',72,'全唐诗/poet.song.66000.json','["繅絲未緣魚，有絲生網心。", "弦木以爲弧，鳥獸不安林。", "大鈞本無事，物類亦愔愔。", "誰令一機駭，萬變起相尋。", "焚木豈人火，棄沙非外金。", "如何巧詐子，尚欲峻而深。"]'),
('a3051ff3-74e8-4e8d-9437-f988b7cd8373','晚春獨酌有感  其一','張耒','宋','宋诗','song-poetry','','[]','春晏巖谷秀，喬木環我居。',96,'全唐诗/poet.song.66000.json','["春晏巖谷秀，喬木環我居。", "引此西澗泉，漍漍漱我除。", "危橋跨方池，修竹萬有餘。", "人閒午陰靜，鳥下驚游魚。", "清風掃我堂，吏案無文書。", "手携金仙經，諷誦自卷舒。", "身閑去道近，地僻與世疏。", "何須緩巧頰，摇曳王門裾。"]'),
('6ad21447-39c9-4ab8-88a4-8b008889f27c','晚春獨酌有感  其二','張耒','宋','宋诗','song-poetry','','[]','誰謂我無友，蕭然山谷間。',96,'全唐诗/poet.song.66000.json','["誰謂我無友，蕭然山谷間。", "修竹乃佳客，清風如妙言。", "擷彼林間筍，致酒方池邊。", "惟時春服成，花葉猶斑斑。", "月出我已醉，扶歸不知眠。", "洒然中夜醒，起聽西澗泉。", "世累乍去念，放歌心浩然。", "功名付長嘯，持用樂目前。"]'),
('2af0c795-f803-4814-a2fe-d352f0aee462','糶官粟有感','張耒','宋','宋诗','song-poetry','','[]','持錢糶官粟，日夕擁公門。',96,'全唐诗/poet.song.66000.json','["持錢糶官粟，日夕擁公門。", "官價雖不高，官倉常若貧。", "兼并閉囷廩，一粒不肯分。", "伺待官粟空，騰價邀吾民。", "坐視既不可，禁之益紛紜。", "擾擾田畝中，果腹才幾人。", "我欲究其源，宏闊未易陳。", "哀哉天地間，生民常苦辛。"]'),
('f649983e-6840-4df7-ad20-a64175c85e57','將離柯山十月二十七日','張耒','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','去此定有期，逝將泛扁舟。',96,'全唐诗/poet.song.66000.json','["去此定有期，逝將泛扁舟。", "千里須聚糧，尚復少遲留。", "雖有隸囚籍，聊喜脫遐陬。", "問我行何之，岱宗古東州。", "念我所居堂，蓬茅委荒丘。", "西窗兩芭蕉，誰見春萌抽。", "園梅粲已發，門掩懶重游。", "今晨一長歎，離思浩難收。"]'),
('88a86760-3f74-42e1-94d5-0d1f818b70ba','視盜之南山','張耒','宋','宋诗','song-poetry','','[]','窮冬策羸馬，祇役走南山。',252,'全唐诗/poet.song.66000.json','["窮冬策羸馬，祇役走南山。", "原野勢忽盡，並溪屢回沿。", "列石如牛羊，流泉鳴佩環。", "兩峽忽壁立，仰失團圓天。", "淺澗凍欲絕，層冰洌我泉。", "躋攀越前嶺，危石萬丈懸。", "衣薄近翠壁，雲低上層顛。", "谷深日無輝，地絕風更寒。", "百里不逢人，我徒互悲歎。", "但見女几峰，萬尋戈劍攢。", "淋漓鎖冰雪，冷射狐裘穿。", "日暮投主人，茅茨起孤烟。", "燃薪不計束，未解手足拳。", "主人前致辭，問官來苦艱。", "我答豈得已，王事不可閑。", "饋我脫粟飯，殷勤爲加餐。", "山家無酒肉，粗糲味亦甘。", "月出萬嶺光，夜歸霜滿鞍。", "迴視所歷途，猿鳥應愁顔。", "暗想酸兩股，夜眠驚夢魂。", "人生亦可貴，何事戀微官。"]'),
('db3a44a9-ede5-462a-9ed0-f6929e76df18','冬日自福昌之澠池','張耒','宋','宋诗','song-poetry','','[]','羣崗洛陽西，勢若海浪翻。',192,'全唐诗/poet.song.66000.json','["羣崗洛陽西，勢若海浪翻。", "連嶺起我左，層阜當我前。", "采如獸騰突，繚若蛇蜿蜒。", "外高陟縹緲，却下逼重淵。", "老崖忽中斷，俯視毛骨寒。", "百丈未見底，立土如巖巒。", "登高望四垠，目斷無平川。", "崩騰萬馬羣，出沒相後先。", "雖有貔虎軍，顧步安得前。", "我觀絕塞處，塊土萬雉堅。", "崤澠自古險，秦人有重關。", "信哉天作固，扃鍵誰敢干。", "時平戰伐息，地闢村落閑。", "堆阜何茫茫，耕桑莽相連。", "平生喜壯觀，弔古重悲歎。", "山川只自爾，興廢何多端。"]'),
('4758369d-b9e3-4b3c-b625-7a1ffd89dad3','宿峻極下院','張耒','宋','宋诗','song-poetry','','[]','天寒蒼山高，野寺在山麓。',120,'全唐诗/poet.song.66000.json','["天寒蒼山高，野寺在山麓。", "長林繫我馬，古屋留客宿。", "空巖陰風豪，達旦號古木。", "夢爲神仙遊，境界脫塵俗。", "平明出戶望，曉日在巖腹。", "冰霜刮昏霾，萬丈攢翠玉。", "山行日已久，常苦見未足。", "猶同賢者處，愈久愈可欲。", "傳聞峻極嶺，千里如在目。", "愧爾巖上僧，窮年玩幽獨。"]'),
('8751b918-91d3-481e-a5f0-958ce0cbc390','下崿嶺','張耒','宋','宋诗','song-poetry','','[]','陰風吹我衣，左右入石壁。',120,'全唐诗/poet.song.66000.json','["陰風吹我衣，左右入石壁。", "石色寒更青，蕭蕭響枯櫪。", "深行方慘淡，路盡兩崖闢。", "羣山岔然來，千里平若席。", "茲惟東周壤，氣象雄萬國。", "山河拱別都，自古帝皇宅。", "轘轅天設險，坐制萬夫力。", "周公卜遷鼎，彼肯事無益。", "天寒僮僕愁，歲晚霜霰逼。", "緬思垂堂戒，攬轡三歎息。"]'),
('2f8ce927-6ce9-4429-8197-c2b794e162e7','初離淮陰聞汴水已下呈七兄','張耒','宋','宋诗','song-poetry','','[]','朝離淮陰市，春水滿川平。',120,'全唐诗/poet.song.66000.json','["朝離淮陰市，春水滿川平。", "依依道邊人，送我亦有情。", "千里積雪消，布穀催春耕。", "人家遠不見，柳色烟中明。", "輕舟鳴桹子，野靜遙相應。", "連網收潑剌，嘉魚飽南烹。", "平生晤語歡，促膝聯弟兄。", "相逢古難得，白髮老易生。", "檣烏飛更北，汴柳綠相迎。", "從今淮山夢，却在鳳凰城。"]'),
('c8f0c183-fda3-422a-a4ae-f378a02dbc22','次韵七兄龜山道中','張耒','宋','宋诗','song-poetry','','[]','連山赴靈龜，石脚疊如積。',96,'全唐诗/poet.song.66000.json','["連山赴靈龜，石脚疊如積。", "巍峨黄金剎，負此鰲背力。", "孤舟繫東風，淮雨暗春色。", "朝來一悵望，別此巖下石。", "危檣鼓帆腹，輕櫓跨浪脊。", "林分岸忽盡，鳥去天末極。", "遠游快新矚，勝事旋陳迹。", "悵此故里違，塵駕何時息。"]'),
('16629073-4d77-4833-b6e9-252515a20a16','龜山水陸院','張耒','宋','宋诗','song-poetry','','[]','院靜步柏影，庭虛聞塔鈴。',168,'全唐诗/poet.song.66000.json','["院靜步柏影，庭虛聞塔鈴。", "連龕香慘淡，古榜金青熒。", "山背負華殿，淮身朝廣庭。", "旛花龍護法，梁棟神扶傾。", "緬懷開山人，天眼照廢興。", "一庵檀施集，百堵神鬼驚。", "支祁萬古穴，石老深潭清。", "坐令金仙力，鎮此水府靈。", "我來望春野，高閣近青冥。", "白髮老比丘，俯僂困逢迎。", "豈無世外人，燕坐守無名。", "重堂百僧會，合有菩薩行。", "平生一鉢意，長歲百慮更。", "狂逃不知返，勝地念浮生。"]'),
('47f5e5da-d882-437d-94cc-76ce7d862e11','曲河驛初見嵩少','張耒','宋','宋诗','song-poetry','','[]','我行日益深，所遇日益好。',156,'全唐诗/poet.song.66000.json','["我行日益深，所遇日益好。", "森然過絕壁，慘淡石色老。", "層峰乍崩奔，峻峽忽開導。", "清溪瀉兩間，淺瀨浮水鳥。", "縈紆石路窄，構架野橋小。", "娟娟翠篠寒，時見木合抱。", "危亭偶平曠，是日見嵩少。", "峨峨重雲外，傲睨插蒼昊。", "坐令羣山勢，凌轢困籍蹈。", "平生忽俗事，丘壑情所好。", "無謀苟自給，薄官廢幽討。", "豈無幽棲士，顧我林下笑。", "會當採芝去，富貴曷足道。"]'),
('ec4fb245-e5f3-46a1-aa51-0ac192551be4','秋懷十首  其一','張耒','宋','宋诗','song-poetry','','[]','西風吹前林，壯士中夜興。',168,'全唐诗/poet.song.66000.json','["西風吹前林，壯士中夜興。", "感此歲月晚，白髮來無情。", "少年讀詩書，意與屈賈爭。", "口談霸王略，銳氣虹霓橫。", "天衢白日開，致主皎丹誠。", "豈懷富貴念，但愧稷契朋。", "栖遲客淮海，憂患相纏嬰。", "憔悴消壯氣，饑寒費經營。", "心期與外物，易失常難并。", "蕭條爲斗粟，貧賤洛陽城。", "我生亦有命，榮辱復何驚。", "但驚歲律遒，慷慨懷平生。", "呼兒致濁酒，長嘯視青冥。", "醉爲梁父吟，吟終誰爲聽。"]'),
('4cd3a3ce-8ce8-48ce-946d-3173eece8b82','秋懷十首  其二','張耒','宋','宋诗','song-poetry','','[]','飄風激浮雲，飛雨來若注。',96,'全唐诗/poet.song.66000.json','["飄風激浮雲，飛雨來若注。", "絺衣逼新凉，感此歲云暮。", "高堂有華簟，坐覺顔色故。", "人情隨炎凉，興廢一何屢。", "鮮鮮中庭菊，華葉日敷布。", "可憐摇落中，爾獨傲霜露。", "官閑隨俗念，歲晚無歡趣。", "惟與青山期，晴明躡芒履。"]'),
('d21d22ac-3aa1-4233-8744-96e648b02664','秋懷十首  其三','張耒','宋','宋诗','song-poetry','','[]','夜靜四聽絕，蟋蟀鳴我堂。',96,'全唐诗/poet.song.66000.json','["夜靜四聽絕，蟋蟀鳴我堂。", "知時爾雖早，嘖嘖竟何傷。", "西風肅萬木，百物皆摧藏。", "爾豈不自得，悲鳴訴中腸。", "寒衣已在椸，紈扇委空床。", "豳詩嗟婦子，入處謹風霜。", "而我獨何成，遠遊悲異鄉。", "出處兩無策，感時空慨慷。"]'),
('1d2dcbf9-e541-4da8-ae5e-0dd80d1d8b19','秋懷十首  其四','張耒','宋','宋诗','song-poetry','','[]','歲暮無所爲，官門聊飲酒。',120,'全唐诗/poet.song.66000.json','["歲暮無所爲，官門聊飲酒。", "家貧乏肴果，擷蔬不盈手。", "要歸一醉爾，甯復計薄厚。", "頹然几案間，樗散忘宇宙。", "古來痛飲人，可是耽醇酎。", "由來困寂寞，聊此娛昏晝。", "紛紛眼前物，泯泯胸中垢。", "當其暫忘去，快若免介胄。", "蕭蕭風入簷，皎皎月當牖。", "歌罷興已闌，感歎還搔首。"]'),
('9c8b1b60-3133-4e82-9247-89b51f5e6a80','秋懷十首  其五','張耒','宋','宋诗','song-poetry','','[]','蟲鳴一何悲，竟夕不能已。',120,'全唐诗/poet.song.66000.json','["蟲鳴一何悲，竟夕不能已。", "缺月能幾何，光輝還暫爾。", "青燈照床帷，解带偃宵寐。", "勞勞隨朝日，既夕聊此憩。", "是非競賢否，榮辱爭賤貴。", "紛然無時停，膏火互煎沸。", "區區竟何有，俯仰終一世。", "癡兒自驕玩，達者已高逝。", "無營謝巧械，咋舌笑愚嗜。", "猶須多貯酒，遲暮聊卒歲。"]'),
('96be27e6-1429-40ef-ac22-1b814d5f2b93','秋懷十首  其六','張耒','宋','宋诗','song-poetry','','[]','西風掃黄葉，零落委我前。',120,'全唐诗/poet.song.66000.json','["西風掃黄葉，零落委我前。", "閉門無來客，空床過午眠。", "床頭亦何有，狼籍古人編。", "琳瑯巧言語，照輝後世傳。", "餘榮更何恃，朽骨但茫然。", "悲哉事無益，辛苦勞生前。", "嗟我方病此，詩書費雕鎸。", "知愚不自已，既痼何由痊。", "霜梧夜槭槭，寒菊朝娟娟。", "胡爲不飲酒，戚戚愁吾年。"]'),
('068a0d43-869d-42b1-a622-dbbd1a2531d2','秋懷十首  其七','張耒','宋','宋诗','song-poetry','','[]','悠悠春與秋，泯泯朝復夜。',96,'全唐诗/poet.song.66000.json','["悠悠春與秋，泯泯朝復夜。", "濟時無遠圖，謀食阻高謝。", "茫茫兩不可，默默私自咤。", "疏弦無悅音，失路有迷駕。", "孟軻竟迂闊，樊子欲耕稼。", "古人不吾待，孑孑欲誰舍。", "詩書頗完緝，官事幸休暇。", "聊從心所樂，此外曷足藉。"]'),
('61894215-b7fe-430e-a0ff-34be6878e103','秋懷十首  其八','張耒','宋','宋诗','song-poetry','','[]','原野日遼闊，南山疏亭亭。',96,'全唐诗/poet.song.66000.json','["原野日遼闊，南山疏亭亭。", "夏雲斂氛翳，秋木呈疏明。", "幽居苦不樂，展步乘朝晴。", "嗟我無羽翼，何由躡崢嶸。", "神仙雖誕漫，可以忘俗情。", "乘桴古亦有，况復凌滄溟。", "浮生既有限，散誕煩冠纓。", "黄精若可採，高揖吾其行。"]'),
('f2eaf416-9f8c-4e02-8594-ed88b6daa790','秋懷十首  其九','張耒','宋','宋诗','song-poetry','','[]','秋風從西來，百草隨委棄。',72,'全唐诗/poet.song.66000.json','["秋風從西來，百草隨委棄。", "如何中庭花，粲粲濯朝霽。", "雖懷遲暮感，獨秀亦云異。", "炎凉各一時，豈必桃李貴。", "遲功有暮祉，銳進或先退。", "由來一氣耳，瑣屑何足計。"]'),
('db1ce6b9-b802-4c90-a56c-fb11ac930dad','秋懷十首  其一○','張耒','宋','宋诗','song-poetry','','[]','吏散門寂寂，蟲鳴夜沉沉。',72,'全唐诗/poet.song.66000.json','["吏散門寂寂，蟲鳴夜沉沉。", "素壁上明月，凉風摇樹陰。", "悲歌忽不愜，感歎涕盈衿。", "寫此牢落懷，默坐彈鳴琴。", "俗耳不好古，古人已非今。", "悲哉曠四海，孑孑無知音。"]'),
('e5dffa08-b4a1-4fbe-9927-981ae507b89f','上元家飲值文安君誕辰','張耒','宋','宋诗','song-poetry','','[]','新正值家節，時雨霽良宵。',72,'全唐诗/poet.song.66000.json','["新正值家節，時雨霽良宵。", "林坰敞梵剎，香烟霾白毫。", "士女傾都出，夾路輪蹄驕。", "誰能衡茅下，寂寞守無聊。", "載御芳蘭饌，無辭玉色醪。", "况值私庭慶，祝壽比蟠桃。"]'),
('c5ec435d-4bf5-4f57-8365-f2a2499a4947','初冬偶成','張耒','宋','宋诗','song-poetry','','[]','清商忽已謝，環堵緬清冬。',72,'全唐诗/poet.song.66000.json','["清商忽已謝，環堵緬清冬。", "今晨起何早，肅氣淒房櫳。", "繁霜凜欲結，霽霧迷長空。", "理畦曉蔬盡，收果高林空。", "六年淮陽客，歲歲風景同。", "吁嗟吾老矣，撫事思無窮。"]'),
('ba2a1f7d-dc6e-481f-9768-12808fac7846','寄集節二首  其一','張耒','宋','宋诗','song-poetry','','[]','陳侯氣飄飄，誰敢易挹酌。',168,'全唐诗/poet.song.66000.json','["陳侯氣飄飄，誰敢易挹酌。", "俊如摶風鷹，清如唳霜鶴。", "高懷落俗事，見者初駭愕。", "須臾發其有，珠玉隨洒落。", "浩然謝畦畛，誰不愛而樂。", "論交嗟我晚，玉手未暖握。", "別來星一周，庭竹再飄籜。", "洛陽誰知子，恐未免寂寞。", "崢嶸胸中氣，誰與發其鑰。", "知心古所少，獻厚報或薄。", "興懷每念此，中夜情抱惡。", "雖然千金璧，豈得常在璞。", "山城一尊酒，子去誰酬酢。", "高歌遣我思，長嘯觀寥廓。"]'),
('8b8660cd-1987-43f6-8868-ecad13ff8065','寄集節二首  其二','張耒','宋','宋诗','song-poetry','','[]','北風號空庭，山雪鳴急霰。',192,'全唐诗/poet.song.66000.json','["北風號空庭，山雪鳴急霰。", "是時我與子，傾蓋初相見。", "相逢兩恨晚，語罷喜復歎。", "明燈照紅爐，杯酌方爛漫。", "劉公摩霜鬢，氣若初捷戰。", "喜我兩人交，深杯手持勸。", "縱橫恣談笑，一醉便侵旦。", "想子病酒容，蓬頭不能飯。", "那知會日少，告別不容戀。", "出門送子歸，慘若失侶雁。", "終朝或不語，妻子怪相問。", "別來三得書，日月去如箭。", "栗亭在何處，山川浩千萬。", "吾將理南棹，遂我江湖願。", "兩如隨風雲，那復計聚散。", "遲君秣驪駒，別我過窮縣。"]'),
('7c3d1381-e6e8-4ed9-bf6a-011b0c0c6878','食杞','張耒','宋','宋诗','song-poetry','','[]','江皋春氣足，佳杞蕃新苗。',108,'全唐诗/poet.song.66000.json','["江皋春氣足，佳杞蕃新苗。", "老枿飽霜露，餘滋發柯條。", "青青被修岡，若若緣空壕。", "僮歸必盈筐，一杯勸爾勞。", "神農不吾期，夸譽何忉忉。", "堅筋及奔馬，瑩目察秋毫。", "餘功補陽幹，清利勝堇椒。", "老臞天隨翁，空斧無脂膏。", "飯成資爾薦，長對顔家瓢。"]'),
('5a7d2c10-98cc-43ba-950a-2b97c3dd26b1','在告家居','張耒','宋','宋诗','song-poetry','','[]','朝日入寒屋，春風已復來。',108,'全唐诗/poet.song.66000.json','["朝日入寒屋，春風已復來。", "老子朝睡足，悠然有好懷。", "冬溫抱微疾，亦不禁酒盃。", "悠悠三酌後，徑使牢愁開。", "惱我以貧賤，我心如死灰。", "誘我以富貴，我視如塵埃。", "以此行世間，何往願不諧。", "呼奴具鱐脯，蔬果粗安排。", "瓶中幸未燥，不醉何歸哉。"]'),
('95867323-e6c5-4f6e-a792-fd4a510bb66a','臘月十八日蚤苦寒與家婦飲','張耒','宋','宋诗','song-poetry','','[]','寒夜不可旦，老鷄鳴苦遲。',96,'全唐诗/poet.song.66000.json','["寒夜不可旦，老鷄鳴苦遲。", "晨興出戶視，風折山樹枝。", "最愛堂東梅，洌寒亦弄姿。", "夜來月中影，窺我讀書帷。", "中庭石井欄，晨汲氣如炊。", "今日復何事，環佩聯冰澌。", "瓷罌有芳醇，庖舍具鮮肥。", "地爐熾新炭，三酌對山妻。"]'),
('f3b521ca-bd1e-4349-b2fd-faa9588e0cd9','余謫居齊安寓郡東佛舍而制不得逾歲今冬遂移居因遣秬秸料理新居作詩示之','張耒','宋','宋诗','song-poetry','','[]','孟冬寒氣至，北風羣木衰。',96,'全唐诗/poet.song.66000.json','["孟冬寒氣至，北風羣木衰。", "微霖墮簷瓦，老客卧先知。", "二年蕭寺客，巾履忽復移。", "誰令簡書畏，易此鷦鷯枝。", "冥冥造化中，毫釐陰有司。", "念此雖細事，亦非人所爲。", "東窗頗明爽，洒掃吾遨嬉。", "濁酒爲余辦，勿使歎空巵。"]'),
('6e852206-d79e-4582-be50-00f674c0f976','自乾明移居柯山何氏第令秬秸先葺所居','張耒','宋','宋诗','song-poetry','','[]','吾居最易足，容膝便有餘。',96,'全唐诗/poet.song.66000.json','["吾居最易足，容膝便有餘。", "平生一畝宮，游宦乖所圖。", "謫官求便安，僦舍柯山隅。", "灑掃勤汝力，真成野人居。", "棲鴻媚夜渚，待旦志在塗。", "栖遲聊復爾，本不計憂娛。", "惟此東窗下，可以陳圖書。", "三酌便陶然，何者爲吾廬。"]'),
('1a1a8223-2c8c-44a4-8cfb-e625fb28765f','十月十二日夜務宿寄內','張耒','宋','宋诗','song-poetry','','[]','夜寒欺老人，展轉睡不足。',72,'全唐诗/poet.song.66000.json','["夜寒欺老人，展轉睡不足。", "長年怕爲客，況此空齋宿。", "嗈嗈度雲雁，瑟瑟受霜竹。", "凍骹冷如植，未覺重衾燠。", "天明起盥櫛，淡日初照屋。", "寄聲家具酒，買魚烹雁鶩。"]'),
('89a928a4-5dd5-4b30-a085-008038a0ecb8','遷居羅溪潘邠老昆仲比以火驚相見殊闊作詩調之','張耒','宋','宋诗','song-poetry','','[]','畢方逐未去，里巷時狂走。',60,'全唐诗/poet.song.66000.json','["畢方逐未去，里巷時狂走。", "念君簞瓢外，顔室空無有。", "誤憂黎元謾，烜赫驚戶牖。", "我雖厭遷次，寒突黔已久。", "平生昧奇字，安得君載酒。"]'),
('ddf9408d-64f7-44b3-aef1-ba91cbe57189','東園','張耒','宋','宋诗','song-poetry','','[]','浮雲蔽亭午，白日成蕭森。',72,'全唐诗/poet.song.66000.json','["浮雲蔽亭午，白日成蕭森。", "餘凉入坐隅，萧洒散煩襟。", "孟夏愛吾屋，秀木成佳陰。", "衆果頗已成，永日鳴山禽。", "杖履時亦到，逍遙忘滯淫。", "舉頭天雨霽，落日低遙岑。"]'),
('6f4b9c39-c7e9-4652-a6ed-0496af94d31b','步蔬圃','張耒','宋','宋诗','song-poetry','','[]','荒城繁草木，落日下牛羊。',120,'全唐诗/poet.song.66000.json','["荒城繁草木，落日下牛羊。", "巍亭俯蔬圃，秋物半青黄。", "敢愛雄雞冠，殷鮮如激昂。", "黄葵貴且麗，薄夜掩其房。", "低篁掩蟋蟀，枯葦巢螳螂。", "落落中畦棗，垂實半老蒼。", "深行亂飛蝶，時亦掇芳香。", "況復携婦子，笑言何樂康。", "歸溪踏新月，到家燈燭光。", "田園興偶動，疏懶意何長。"]'),
('7415b4e2-0e7f-4531-b5f3-cd92d96078f2','步下四望亭至東坡柳逕訪邠老不遇','張耒','宋','宋诗','song-poetry','','[]','北下四望嶺，兩山中曠平。',108,'全唐诗/poet.song.66000.json','["北下四望嶺，兩山中曠平。", "縈紆蟠逕術，迤靡分溝塍。", "林間樵汲路，壠外牛羊鳴。", "落景急晚舂，淺泥聞耦耕。", "餘紅猶落落，高綠或亭亭。", "柳間見衡門，欹屋尚崢嶸。", "主人掩關去，春蕪空復青。", "論文挈兒曹，得句懷友生。", "安得輞川翁，畫此十幅屏。"]'),
('2b728a9d-667a-4991-a9d7-e5eca3d7742a','上巳日洛岸獨遊寄陳永寧','張耒','宋','宋诗','song-poetry','','[]','風雩感賢游，嘉節偶乘興。',96,'全唐诗/poet.song.66000.json','["風雩感賢游，嘉節偶乘興。", "人稀好鳥語，麥秀春野靜。", "澄波漾清洛，游子渡明鏡。", "南山夜來雨，雲日淡相應。", "解鞍憩高柳，覽物動新詠。", "優游徒侶喜，豐熟蔬果盛。", "官閑省文檄，俗古少喧競。", "乘閑輒獨游，茲焉樂吾性。"]'),
('177d3133-6aa3-410e-8b55-508adf13dbf0','渡洛游三鄉書所見','張耒','宋','宋诗','song-poetry','','[]','重雲蔽南山，遠見山雨白。',120,'全唐诗/poet.song.66000.json','["重雲蔽南山，遠見山雨白。", "我行山之北，便與雲雨隔。", "西風來如奔，零亂雲物拆。", "驅除信果决，霶霈絕餘滴。", "收雷如歸師，蹄轍度南磧。", "羣峰湧地出，掀蕩無留碧。", "暮投三鄉寺，落日在東壁。", "鐘鳴高閣晚，野迥見歸翼。", "還家晚川靜，秋月未生魄。", "聊資覽物態，應用慰行役。"]'),
('592e04c6-3da2-49e0-8fc2-3d5c7ba82da5','游白馬寺','張耒','宋','宋诗','song-poetry','','[]','秋林轉層崖，步踏落葉響。',288,'全唐诗/poet.song.66000.json','["秋林轉層崖，步踏落葉響。", "森森夾路竹，矗矗羽林仗。", "精廬隠深塢，門啟臺殿敞。", "纍纍霜果懸，落落寒木壯。", "房深燈火暖，縱飲頗酣暢。", "山寒夜已深，嶺白月微上。", "天明寺南去，幽路隘而昉。", "林分逕忽斷，淺澗闊逾丈。", "崩奔被澗石，大小非一狀。", "丸丸列囷廩，落落排甕盎。", "鳴泉走石罅，聯絡弄清漲。", "喧頹競飛漱，派瀉或平漾。", "羣行命朋儔，困息植吾杖。", "沿松見奇鼠，石蟹侑朝餉。", "深行耳目靜，擠險誰復讓。", "寒聯老木陰，暖值丹崖曠。", "秋暉墮平野，暮鳥啼青嶂。", "徜徉未知返，欲去意先愴。", "膏粱與薇蕨，美惡隨所尚。", "當其兩自得，厭滿絕餘望。", "乃知山林樂，豈爲隠者妄。", "況吾不事事，枯槁理則當。", "遑遑施仁義，此固聖賢量。", "我自沮溺徒，疏頑安可强。"]'),
('dc2316ba-b57e-46f0-95de-d9d406eb5dc8','獨遊崇化寺題觀音院','張耒','宋','宋诗','song-poetry','','[]','默默苦不展，駕言陟崇崗。',120,'全唐诗/poet.song.66000.json','["默默苦不展，駕言陟崇崗。", "人遠塵坌息，高門開寶坊。", "華簷敞虛殿，喬木護修廊。", "閒庭引幽步，偃息得茲堂。", "惟時炎火衰，清秋朝暮凉。", "窗虛竹色靜，風遠松聲長。", "遙山露雲表，遠水連天光。", "獨遊不自得，遐眺有餘傷。", "留滯感華歲，登臨思故鄉。", "言歸日已夕，月出林蒼蒼。"]'),
('75ceba26-12b1-40e5-8eb8-60ed05f500c2','宿鳳翅山懸泉寺','張耒','宋','宋诗','song-poetry','','[]','秋山晚景凉，幽路轉石壁。',264,'全唐诗/poet.song.66000.json','["秋山晚景凉，幽路轉石壁。", "稍知步武峻，漸與鷄犬隔。", "層崖恃我西，懸瀑垂百尺。", "崩騰擣重泓，晝夜碎珪璧。", "天寒行已深，嶺轉客暫息。", "最愛下山泉，潺潺馬蹄側。", "重門敞幽寺，臺殿互開闢。", "野僧三四人，披衣出迎客。", "陰陰修竹靜，下有神龍宅。", "泓澄一畝泉，黯黯萬古色。", "翛然改瞻視，異物如不隔。", "蕭蕭毛髮疏，佇立動神魄。", "雲低秋天陰，木落山日夕。", "房寒燈火青，夜久人語寂。", "通宵淡無夢，起望曉天白。", "山川接周韓，清洛去不極。", "我無軒冕意，野性自夙昔。", "塵埃阻幽好，奔走愧謀食。", "偷閑到丘壑，便欲老泉石。", "君有在籠鶴，豈願潜六翮。", "將歸且復止，既去緩吾策。", "寄語山中人，行當蠟雙屐。"]'),
('9932fa1f-01ae-4765-bfad-329ed55a563c','病瘉登疊嶂樓','張耒','宋','宋诗','song-poetry','','[]','沉疴幸蕭散，登覽慰無聊。',72,'全唐诗/poet.song.66000.json','["沉疴幸蕭散，登覽慰無聊。", "江南春尚早，餘雪冒山椒。", "野梅臨風謝，溪澌映日消。", "晴林鳥聲樂，幽墅水文摇。", "新年人意樂，初霽物華饒。", "共理慚良牧，無政載風謠。"]'),
('1c015a60-e63d-4c8a-bea6-fe40472d6c69','登雙溪閣','張耒','宋','宋诗','song-poetry','','[]','清溪浮天光，北騖而西折。',84,'全唐诗/poet.song.66000.json','["清溪浮天光，北騖而西折。", "羣山合沓來，斷作青玉玦。", "中圍萬家邑，簫鼓樂芳節。", "仲春卉木麗，紅綠晚明滅。", "重樓壓城角，高眺俯木末。", "川雲斷還續，谷鳥鳴復歇。", "興闌未能返，留酌待芳月。"]'),
('9c027aee-550c-4185-aa5a-a1030630b790','淮陽','張耒','宋','宋诗','song-poetry','','[]','淮陽古帝墟，鄙夫少所遊。',96,'全唐诗/poet.song.66000.json','["淮陽古帝墟，鄙夫少所遊。", "最愛城西路，槐榆拱高秋。", "城下古濠水，清澄泓不流。", "嗟哉始封君，千古留一丘。", "西風臛新兔，魚鱉亦易求。", "穀穗如垂珠，松林風颼颼。", "異鄉仍謫官，一步九回頭。", "何時守一廛，白首自鋤耰。"]'),
('49eb4328-a749-4481-bba9-8892406021ee','新開北原','張耒','宋','宋诗','song-poetry','','[]','山深草木多，春夏廢翦剔。',288,'全唐诗/poet.song.66000.json','["山深草木多，春夏廢翦剔。", "北原有高溪，經歲不躡屐。", "陰根走重險，飛蔓密如織。", "交柯不容鳥，老枿頑若石。", "由茲廢登眺，幽致莽蕭瑟。", "杖藜每獨往，駐立爲歎息。", "窮秋九月衰，霜過萬葉赤。", "北風始驅除，蒙翳遭搏擊。", "乘時集吾徒，斤斧必謹飭。", "攀緣窮翦伐，上下恣搜剔。", "霜芒落勁節，巨劚剖堅植。", "蛟龍脫鱗鬚，犀兕遺骨革。", "薪蒸不足道，椽棟固委積。", "紛紜一日勞，既暮岩藪闢。", "寒篁露幽翠，佳木呈秀色。", "高臺忽平敞，快步失荆棘。", "巉巉女几峰，次第見晴碧。", "遙村暮烟合，烏鳥寒寂歷。", "縱橫目前景，指顧歸咫尺。", "茲焉遂忘返，漸可携尊席。", "人間有能事，功效在勤力。", "惡深當痛治，穢盡善斯得。", "經年滯窮谷，庶以娛朝夕。", "題詩寄初終，撫事心有激。"]'),
('0206b4e3-b8e9-42e7-b8ab-fb13b77c1a4b','春遊昌谷訪李長吉故居','張耒','宋','宋诗','song-poetry','','[]','連山忽中開，呀若敞雙戶。',144,'全唐诗/poet.song.66000.json','["連山忽中開，呀若敞雙戶。", "清泉瀉中間，行子並溪去。", "蒼崖左右壁，田壠亦棋布。", "渠流漲春漪，鳴澗轉芳嶼。", "鷄豚見茅屋，負檐隠微路。", "竹塢藹青葱，花岩被紅素。", "仲春雨新斂，晴日破氛霧。", "南山當其門，列嶂儼環護。", "深行不知厭，捨馬時獨步。", "欣然耳目愜，遂我麋鹿趣。", "朝隨浮雲來，歸轡月中度。", "惆悵錦囊生，遺居無復處。"]'),
('6eb6d931-751a-49bb-a54f-81981142390c','寄題何戢秀才琬琰堂','張耒','宋','宋诗','song-poetry','','[]','幽人築淇澳，不與世相聞。',144,'全唐诗/poet.song.66000.json','["幽人築淇澳，不與世相聞。", "獨携千卷書，過於骨肉親。", "辛苦作室堂，插架如魚鱗。", "時時體不住，一遇千載人。", "山川兵火後，墟廟金石存。", "消磨餘紙墨，幻滅去無痕。", "功名但如此，知子道可尊。", "不遺世一毫，以全與其身。", "包醜傅黛膏，百態售笑顰。", "誰能雙蛾眉，閉戶自貴珍。", "鄙人有夙尚，願與幽侶敦。", "他年抱健犢，聽嘯入蘇門。"]'),
('d166e3a3-97a9-4a1a-9e8e-46617dfff645','讀管子','張耒','宋','宋诗','song-poetry','','[]','夷吾相桓公，豈復偶際會。',144,'全唐诗/poet.song.66000.json','["夷吾相桓公，豈復偶際會。", "觀其平生心，身已有所委。", "天方困生民，弔伐實在己。", "求居寓所欲，糾與白等耳。", "堂堂東海邦，內政謹疆理。", "南荆北達燕，玉幣走千里。", "仲尼免左衽，自以身受賜。", "孟軻聖之偶，非薄良有謂。", "彼狂後世儒，詆毀恣輕議。", "嗟哉不量分，詎解聖賢意。", "區區彼商鞅，操術良非是。", "爲法昧所從，以身受其弊。"]'),
('bd0ca6e6-1f14-437e-92cd-39e71e7c54da','讀杜集','張耒','宋','宋诗','song-poetry','','[]','風雅不復興，後來誰可數。',240,'全唐诗/poet.song.66000.json','["風雅不復興，後來誰可數。", "陵遲數百歲，天地實生甫。", "假之虹與霓，照耀蟠肺腑。", "奪其富貴樂，激使事言語。", "遂令困饑寒，食糲衣掛縷。", "幽憂勇憤怒，字字倒牛虎。", "嘲詞破萬家，摧拉誰得禦。", "又如滔天水，决洩得神禹。", "他人守一巧，爲豆不能簠。", "君獨備飛奔，捷蹄兼駿羽。", "飄萍竟終老，到死尚爲旅。", "高才遭委棄，誰不怨且怒。", "君乎獨此忘，所惜唐遺緒。", "悲嗟痛禍亂，欲取彝倫敘。", "天資自忠義，豈媚後人睹。", "艱難得一職，言事竟齟齬。", "此心耿可見，誰肯浪自苦。", "鄙哉淺丈夫，夸己訕其主。", "文章不知道，安得擅今古。", "光焰萬丈長，猶能伏韓愈。"]'),
('9e4a0a26-fc67-4cec-bb98-637af5e9a2e1','石曼卿三佛名大字','張耒','宋','宋诗','song-poetry','','[]','石公神仙狂，脫落隠詩酒。',168,'全唐诗/poet.song.66000.json','["石公神仙狂，脫落隠詩酒。", "餘情到翰墨，落筆聞宇宙。", "崢嶸龜山殿，風雨梁棟舊。", "煌煌三佛榜，鐵柱貫金紐。", "開張宮室正，渾實山嶽厚。", "井水駭龍跧，螘封觀驥驟。", "欲知分毫初，一釂盡數斗。", "墨池氈作筆，神運不知手。", "從容解牛際，蕭散善刀後。", "古來精絕藝，所貴神氣守。", "嗚呼渦水側，爽氣一培塿。", "微工付浩劫，念此終銷朽。", "乾坤一大幻，妄計金石壽。", "惟有龕中人，吾生茲稽首。"]'),
('2de593e3-3fee-486b-b28b-4e875b80bbc1','卧病讀韋蘇州詩呈无咎','張耒','宋','宋诗','song-poetry','','[]','閑官無吏課，未午省中歸。',96,'全唐诗/poet.song.66000.json','["閑官無吏課，未午省中歸。", "端居屬微疾，偃卧度秋輝。", "書帙紛几席，減穀亦清羸。", "庭花敗風雨，晚蝶弄餘姿。", "懷公天津語，夢起江湖思。", "高秋挾健櫓，一與水神嬉。", "上去觸檣閾，奮飛有縶維。", "令人慚髀肉，消盡定何爲。"]'),
('6ba6fcd0-3540-48b3-9ed7-ac286af1f84e','喜寶積智軫道人惠書偈','張耒','宋','宋诗','song-poetry','','[]','南山老禪翁，白浄如水月。',144,'全唐诗/poet.song.66000.json','["南山老禪翁，白浄如水月。", "我初獲親近，解此癡腦結。", "十年歸故里，父老半存滅。", "逢師百如舊，才若旦夜別。", "故知靜能久，豈有火中鐵。", "致身煩熱外，與世作冰雪。", "窮秋長安巷，客子送書札。", "龍蛙不同趣，掬海救其渴。", "平生笑謀食，中路願頗奪。", "猶如伏轅鹿，野性終跳𨁝。", "觸塗惟欲睡，過眼時一噦。", "摩尼本無瑕，塵垢終冀豁。"]'),
('52931223-e9e8-42f0-8bcf-d1513d7b1a37','讀太白感興擬作二首  其一','張耒','宋','宋诗','song-poetry','','[]','瑶姬上帝子，天日與晶光。',72,'全唐诗/poet.song.66000.json','["瑶姬上帝子，天日與晶光。", "萬古巫山中，玉顔照秋江。", "世界一培塿，誰知楚襄王。", "宋生底蟲蛆，妄以己意量。", "我無世上心，乃遊不死鄉。", "與爾等愛惡，朽枯終一藏。"]'),
('de08db07-5ba9-4f8c-b0c7-dac278564b53','讀太白感興擬作二首  其二','張耒','宋','宋诗','song-poetry','','[]','陳王本無頼，少與美人期。',72,'全唐诗/poet.song.66000.json','["陳王本無頼，少與美人期。", "蛾眉作穢血，蠱鬼尚何知。", "乃復結綢繆，佇車心傷悲。", "幻滅猶欲取，哀哉一癡兒。", "千年化異物，雙作鴛鴦飛。", "終然隨大化，飄蕩今何之。"]'),
('3295f267-3449-47e5-b553-61be2cee503d','讀唐書二首  其一','張耒','宋','宋诗','song-poetry','','[]','隋文方混一，自謂垂無疆。',72,'全唐诗/poet.song.66000.json','["隋文方混一，自謂垂無疆。", "安知房之喬，拱立待其亡。", "哲人妙觀世，俗慮固不長。", "我知蒲柳衰，寧待遘風霜。", "奇姿終英發，起驂龍鳳翔。", "巍巍貞觀績，千載配虞唐。"]'),
('5fa0ccc2-7c88-4de2-a9ac-6940b6f1b4f4','讀唐書二首  其二','張耒','宋','宋诗','song-poetry','','[]','二張挾嬖寵，聲勢各滔天。',96,'全唐诗/poet.song.66000.json','["二張挾嬖寵，聲勢各滔天。", "蛇鼠依城社，自謂終千年。", "天道惡滿盈，五龍忽騰騫。", "斷頭誰救汝，猳豚尸道邊。", "擊狗不擊首，反噬理必然。", "智勇忽迷方，脫匣授龍泉。", "區區薛季昶，先事僅能言。", "留禍啟臨淄，敗謀豈非天。"]'),
('2ef3a855-2504-4df0-a93e-57af5aa8901c','睡起效韋蘇州','張耒','宋','宋诗','song-poetry','','[]','睡足起無事，開扃步中園。',72,'全唐诗/poet.song.66000.json','["睡足起無事，開扃步中園。", "中園復何有，花草藹已繁。", "飛紅被行路，山鳥時一喧。", "時雨副耕稼，農事起郊原。", "仰欣天時好，俯驚歲月奔。", "自憐栖遲者，守寂沒亡言。"]'),
('9f46d8e9-b0fa-4836-bd7a-2732fbc37f6c','飲酒擬柳子厚','張耒','宋','宋诗','song-poetry','','[]','澤國多水氣，日西春尚寒。',72,'全唐诗/poet.song.66000.json','["澤國多水氣，日西春尚寒。", "窮居無樂事，且復開清樽。", "一酌召和氣，三觴失愁顔。", "百憂如崩雲，天地爲我寬。", "采采中田杞，愈食仍甘餐。", "登盤自有味，何必盛炮燔。"]'),
('758191de-2a5a-4ee7-929c-b3aff4ab9dd9','何斯舉惠酒','張耒','宋','宋诗','song-poetry','','[]','孟夏飲燒酒，窮居莫致之。',72,'全唐诗/poet.song.66000.json','["孟夏飲燒酒，窮居莫致之。", "扣門聞好語，出應自披衣。", "雙榼儼在門，使者前致詞。", "斂衽受嘉貺，敬此旨且時。", "且喜尊不燥，安得計淳漓。", "但恐昧奇字，令人愧鴟夷。"]'),
('d43b71bb-5b2a-47fd-82d8-80a345eefcf1','文周翰邀至王才元園飲','張耒','宋','宋诗','song-poetry','','[]','朝衫衝曉塵，歸帽障夕陽。',216,'全唐诗/poet.song.66000.json','["朝衫衝曉塵，歸帽障夕陽。", "日月馬上過，詩書篋中藏。", "心疑長安人，一一如我忙。", "城西有佳友，延我步閑坊。", "入門見主人，謝客無簪裳。", "蒲團烏皮几，密室留妙香。", "門前佳木陰，堂後羅衆芳。", "飯客炊雕胡，旨酒來上方。", "盈盈雙鬟女，身小未及床。", "執板歌一聲，賓主無留觴。", "嗽井消午醉，掃花坐晚凉。", "主翁塵外人，三十辭明光。", "閉門自灌園，種花見老蒼。", "有才不試事，歸卧野僧房。", "知君非徒然，顧我不能量。", "始知同一國，喧靜自相忘。", "衆綠結夏帷，老紅駐春妝。", "何惜君馬蹄，坐令風雨狂。"]'),
('bde05a8a-8ecf-4c7b-affd-b8d98626a50a','寺晚','張耒','宋','宋诗','song-poetry','','[]','春寒掩古寺，遲日轉修廊。',96,'全唐诗/poet.song.66000.json','["春寒掩古寺，遲日轉修廊。", "古殿流塵暗，空庭碧草芳。", "中有搘筇者，非醉亦非狂。", "謫官滄江上，已換一炎凉。", "春來不出門，蔬飯守禪堂。", "不知門外花，風雨知在亡。", "興來時展卷，睡足自焚香。", "清吟嘗旨酒，疏懶味何長。"]'),
('7a2c420f-739f-4897-9f85-ab873b6dbb23','辛未立春','張耒','宋','宋诗','song-poetry','','[]','彩勝耀朝日，歡言立新春。',72,'全唐诗/poet.song.66000.json','["彩勝耀朝日，歡言立新春。", "朝陽披宿靄，頗覺天地溫。", "蔬盤簇細甲，相勸御芳辛。", "誰云冰霜底，微綠還陳根。", "我居雙老槐，對聳蒼龍鱗。", "歲窮益慘淡，何以慰老人。"]'),
('5a92b0df-04a3-486d-97f9-0b1912cf8b40','三更','張耒','宋','宋诗','song-poetry','','[]','三更月暈合，定知明日雨。',72,'全唐诗/poet.song.66000.json','["三更月暈合，定知明日雨。", "開門已蕭颯，寒氣侵庭宇。", "東風變淒凜，閉戶思室處。", "頼茲尊有酒，細酌供燕語。", "斗杓行指卯，雖寒能幾許。", "惟應園林好，新霽千花吐。"]'),
('c545875a-28fb-4b64-a46a-622596793880','正月二日探春','張耒','宋','宋诗','song-poetry','','[]','青春來幾時，臘雪消未已。',120,'全唐诗/poet.song.66000.json','["青春來幾時，臘雪消未已。", "蒼茫陳根中，新綠已映趾。", "高風變冰霜，和氣從此始。", "青芒綴蒲柳，紅粒妝桃李。", "融泥發新陽，暖日動生意。", "經年不窺園，偶此携婦子。", "提筐擷野甲，若苦寒蔬美。", "新年酌尊酒，佳節聊燕喜。", "優游自有趣，朝市苦多事。", "閑暇不易求，寧須歎留滯。"]'),
('2485753c-ce65-4e7e-a71b-6f1aa7918a3a','端居二首  其一','張耒','宋','宋诗','song-poetry','','[]','舍東日初上，堂南雪已消。',72,'全唐诗/poet.song.66000.json','["舍東日初上，堂南雪已消。", "鳥聲弄新霽，春風動柳條。", "學道心未降，端居生寂寥。", "佳人不可挹，芳物爲無聊。", "夕扉還自掩，彎月已翹翹。", "黯黯長安夜，愁思悵迢迢。"]'),
('6a68d9d7-ae7e-43aa-acc3-2f03e0cb12e8','端居二首  其二','張耒','宋','宋诗','song-poetry','','[]','餘寒羞老木，慘淡氣未平。',60,'全唐诗/poet.song.66000.json','["餘寒羞老木，慘淡氣未平。", "王國富車馬，士女競新正。", "風埃息九陌，紈綺艷重城。", "燈稀夕烟重，斗轉夜寒生。", "倚楹復何待，依依空復情。"]'),
('71a83d77-f960-4eb1-b8ed-7af31a4a41c7','四月之初風雨淒冷如窮秋兀坐不夜堂二首  其一','張耒','宋','宋诗','song-poetry','','[]','東君已成歸，風雨爲之殿。',72,'全唐诗/poet.song.66000.json','["東君已成歸，風雨爲之殿。", "夜來柯山溜，深射交百箭。", "可憐東園花，收拾無一片。", "開門不能出，徑滑那得踐。", "還歸酌卯酒，佐酌有藜莧。", "重思理貂裘，未用愁紈扇。"]'),
('9003360b-8e19-4545-a760-be97cacec563','四月之初風雨淒冷如窮秋兀坐不夜堂二首  其二','張耒','宋','宋诗','song-poetry','','[]','風雨四月初，正作窮秋寒。',108,'全唐诗/poet.song.66000.json','["風雨四月初，正作窮秋寒。", "朱明方更候，陰沴時相干。", "陰陽天自便，寒暑無必然。", "玄冥與祝融，政事誰得專。", "江鄉累歲饑，一飽望今年。", "不知誰不仁，探喉奪其餐。", "柯山窮老人，方暑愁衣單。", "似聞林筍立，矗矗戈戟攢。", "但知飲美酒，折取共朝盤。"]'),
('bdea9d56-227d-4240-92ac-67327657938d','夏夜二首  其一','張耒','宋','宋诗','song-poetry','','[]','一雨洗空曠，肅然天地秋。',96,'全唐诗/poet.song.66000.json','["一雨洗空曠，肅然天地秋。", "陰陽有至信，殘暑逝不留。", "中夜事忽變，西風延蓐收。", "雲雷西北來，瀰漫布九州。", "萬生息惔焚，我疾亦已瘳。", "起哦不待曉，暗步禪堂幽。", "落月傾屋西，候蟲鳴不休。", "坐令百感集，歲晏此淹留。"]'),
('f3ad8e6b-eec1-4052-84c3-3cbc0e09be16','夏夜二首  其二','張耒','宋','宋诗','song-poetry','','[]','受暑若作釜，付之無如何。',72,'全唐诗/poet.song.66000.json','["受暑若作釜，付之無如何。", "豈陰陽知爭，變起一剎那。", "西風卷屋茅，澍雨如江河。", "振衣欲露坐，濯此寒滂沱。", "烹魚曉沽酒，醉卧仰屋歌。", "歲月不待人，吾年已蹉跎。"]'),
('2d6d8564-e7f5-487b-987f-04cb1a4b81fa','十月七日晨起','張耒','宋','宋诗','song-poetry','','[]','山鴉鳴曉晴，寒日在蓬蓽。',120,'全唐诗/poet.song.66000.json','["山鴉鳴曉晴，寒日在蓬蓽。", "老人欣然起，搆火溫小室。", "室中空無有，掃榻對像佛。", "還觀舊文字，塵土暗編帙。", "一杯徑就醉，四體寒若失。", "隔窗即山麓，寒木鳴瑟瑟。", "江民旱累歲，流冗東就食。", "蛈蝗食陳蔡，千里無草色。", "客來談世事，亹亹語千百。", "客去深閉門，頹然無我責。"]'),
('671a04c6-5aa1-42fa-970e-085bc4695355','衰荷','張耒','宋','宋诗','song-poetry','','[]','衰荷有餘姿，秋水清更急。',72,'全唐诗/poet.song.66000.json','["衰荷有餘姿，秋水清更急。", "木落天宇寬，庭虛山氣入。", "寒魚漸受釣，野果晴可拾。", "幽居無餘營，但與山水習。", "濟時無良謀，戎陳畏戈鈒。", "端坐閱歲時，多慚微祿及。"]'),
('ca1ac7bc-32c6-4204-b61e-22bf2c642067','入伏後三日','張耒','宋','宋诗','song-poetry','','[]','老火熾而焰，端能流弱金。',72,'全唐诗/poet.song.66000.json','["老火熾而焰，端能流弱金。", "清秋有微警，西風生薄陰。", "日中無停暉，俯仰忽已沉。", "齊紈不足玩，流景逝駸駸。", "盛衰寧獨行，巾具密相尋。", "蓬茅有佳處，亦足慰人心。"]'),
('22f12755-0d48-4681-a086-154d58da4dbe','畏暑不出','張耒','宋','宋诗','song-poetry','','[]','赫赫三萬里，共煮一鼎湯。',72,'全唐诗/poet.song.66000.json','["赫赫三萬里，共煮一鼎湯。", "蓬茅數椽屋，何處有清凉。", "惟有攝心坐，憩此真道場。", "清虛無一物，焚灼不能傷。", "自我知此趣，兩脚不下堂。", "人皆笑我拙，我亦笑人狂。"]'),
('64f5f7e8-747d-47d7-b545-40c67589e24e','夏至','張耒','宋','宋诗','song-poetry','','[]','長養功已極，大運忽云遷。',72,'全唐诗/poet.song.66000.json','["長養功已極，大運忽云遷。", "人間漫未知，微陰生九原。", "殺生忽更柄，寒暑將成年。", "崔巍干雲樹，安得保芳鮮。", "幾微物所忽，漸進理必然。", "韙哉觀化子，默坐付忘言。"]'),
('f5f66028-e628-4792-8ff7-50797a238102','庵東窗雨霽月出梅花影見窗上','張耒','宋','宋诗','song-poetry','','[]','山頭冷月出，射我幽窗明。',72,'全唐诗/poet.song.66000.json','["山頭冷月出，射我幽窗明。", "屋東有新梅，寒影交疏櫺。", "暗香不可挹，彷彿認繁英。", "耿耿終無言，依依如有情。", "怳疑姑射真，仙馭下我庭。", "姮娥曉西去，滿樹晨霜清。"]'),
('08ef7c7e-e87a-4b93-b6de-9e637b89f7be','疏梅二首  其一','張耒','宋','宋诗','song-poetry','','[]','疏梅落寒晴，高柳暗春夕。',48,'全唐诗/poet.song.66000.json','["疏梅落寒晴，高柳暗春夕。", "低星上蒼寒，遠鐘韵澄寂。", "頗私朝市間，更得闤闠僻。", "且復罷經過，深泥濺馬臆。"]'),
('0ae7a8a9-02c1-437b-87d7-c38973af0c63','疏梅二首  其二','張耒','宋','宋诗','song-poetry','','[]','我貧受寒欺，帖帖爲不出。',48,'全唐诗/poet.song.66000.json','["我貧受寒欺，帖帖爲不出。", "積雨遠市聲，幽居近芳物。", "時禽過我柳，清喙動鳴瑟。", "客去門復扃，低參映林沒。"]'),
('99e5c7a8-916b-4329-a71d-fc532bad6991','黄菊','張耒','宋','宋诗','song-poetry','','[]','黄菊出荒歲，揚揚顔色好。',84,'全唐诗/poet.song.66000.json','["黄菊出荒歲，揚揚顔色好。", "芙蓉不能霜，敗裂不自保。", "君子與小人，於此見其操。", "最憐所種蔬，根葉依畦老。", "朝晡充盤餐，滋味不枯槁。", "鷄鳴鄰里靜，老子起常早。", "呼童速沽酒，無使尊中燥。"]'),
('fb2c464d-b402-4241-9c0c-879c4b0e59c1','次韵錢大尹公庭種菊','張耒','宋','宋诗','song-poetry','','[]','人才困齊量，能尺不能咫。',120,'全唐诗/poet.song.66000.json','["人才困齊量，能尺不能咫。", "誰知錢京兆，獄訟間書史。", "平明吏擁堂，過午掃階戺。", "風威變姦傲，應若度淮枳。", "清秋動高興，庭菊粲可喜。", "栽培豈無情，收拾自棄委。", "客來擷芳秀，歲晏聊爾耳。", "新凉一尊酒，九日意在彼。", "平生經濟手，張趙一泥滓。", "何必餐落英，離憂對蘭芷。"]'),
('8bbde050-d398-4c44-9253-2c5f0f1f14db','堂下幽草','張耒','宋','宋诗','song-poetry','','[]','烈日三萬里，所至壞金石。',60,'全唐诗/poet.song.66000.json','["烈日三萬里，所至壞金石。", "嗟哉庭中草，獨不改佳色。", "日中雖暫萎，晨露發鮮碧。", "深根通九地，變化有微測。", "應知一氣移，不得常炎赫。"]'),
('caf03e22-e37c-4c9a-b6aa-768c4c262af5','詠雙槐','張耒','宋','宋诗','song-poetry','','[]','花開雖可憐，采色不堅久。',156,'全唐诗/poet.song.66000.json','["花開雖可憐，采色不堅久。", "譬如玩冰雪，隨執隨去手。", "可悅則生愛，愛滅惱隨後。", "美好稱不祥，此語端易究。", "中庭兩蒼槐，老枿獨晚秀。", "殘春餘十日，萬葉舒欲覆。", "森森翠羽蓋，植立分左右。", "波濤起風夜，幄幕護炎晝。", "其榮無可悅，衰變亦何咎。", "欲攀無足玩，欲擷無足嗅。", "泊兮初無情，淡也故可守。", "病來捐衆嗜，味道有真覯。", "寄言兩蒼翁，請與汝此壽。"]'),
('bbfa1ac0-3df7-4d0b-b4ea-090e5db08dde','大榆','張耒','宋','宋诗','song-poetry','','[]','高榆百餘年，其大數十圍。',120,'全唐诗/poet.song.66000.json','["高榆百餘年，其大數十圍。", "修柯遏雲日，老枿干虹霓。", "嗟爾擁腫材，大匠已見遺。", "何人失翦伐，養此頑鈍姿。", "夏葉穴蟲蟻，繁柯蔽凉颸。", "寒憑烈風怒，號白陵冬曦。", "鸞鳳不女巢，所藏鴉與鴟。", "吾寧愛彈射，念爾不適宜。", "蟠據起牆屋，斧斤諒難施。", "去惡不慎微，既成安可追。"]'),
('7da0f9fb-79f2-415d-9a1e-59bc0466646e','竹','張耒','宋','宋诗','song-poetry','','[]','自吾居山中，默默無與歡。',120,'全唐诗/poet.song.66000.json','["自吾居山中，默默無與歡。", "朝晡誰相對，頼此青琅玕。", "堂東一畝池，遠分西澗泉。", "蕭蕭一萬竿，結根護池壖。", "婉婉翠鳳凰，舞風照清瀾。", "微飆自天來，新佩鳴已喧。", "王子骨已朽，後來豈有賢。", "諒非聾與盲，敢慢回與騫。", "灌溉養春茁，芟除去其繁。", "終日淡相對，俗車無至門。"]'),
('4996b773-0d2a-4ae9-ab17-6ebdbcc7aa6b','石竹','張耒','宋','宋诗','song-poetry','','[]','真竹乃不華，爾獨艷暮春。',48,'全唐诗/poet.song.66000.json','["真竹乃不華，爾獨艷暮春。", "何妨兒女眼，謂爾勝霜筠。", "世無王子猷，豈有知竹人。", "粲粲好自持，時來稱此君。"]'),
('54af695f-032b-4273-acd7-07e745edeaeb','乞竹贈邠老','張耒','宋','宋诗','song-poetry','','[]','與君共一山，修竹居其間。',96,'全唐诗/poet.song.66000.json','["與君共一山，修竹居其間。", "義當給兩家，潘子不得慳。", "带甲十萬夫，不戰終日閑。", "辱使支敝廬，令我愧滿顔。", "代竹爲洗竹，義取洗益繁。", "乞我萬之一，令君風月寬。", "裒多以益寡，天道自古然。", "詩成復自笑，詩禮資儒姦。"]'),
('4dfb1842-113b-457f-975c-b7c886e2d194','理東堂隙地自種菜','張耒','宋','宋诗','song-poetry','','[]','幽居無一事，隙地自畦蔬。',96,'全唐诗/poet.song.66000.json','["幽居無一事，隙地自畦蔬。", "秋雨忽甲坼，青青千萬餘。", "江鄉盛菘芥，烹咀亦甘腴。", "豈惟供晨餐，庶用備冬葅。", "桓桓左將軍，英氣橫八區。", "邂逅無事時，弛弓曾把鋤。", "矧我放逐者，終年守敝廬。", "諒非勤四體，寓意以爲娛。"]'),
('2fcc0793-9f68-4aa0-90c1-f5e49222a473','種薤','張耒','宋','宋诗','song-poetry','','[]','薤實菜中芝，仙聖之所嗜。',120,'全唐诗/poet.song.66000.json','["薤實菜中芝，仙聖之所嗜。", "輕身彊骨幹，却老衛正氣。", "持錢易百本，僻處多隙地。", "雨餘土壤滋，栽植勤我隸。", "今年時澤足，灌汲免遠致。", "朝畦已芬敷，零落發鮮翠。", "嗟余百不偶，六尺自知愧。", "雖甘老支床，同願壽閱世。", "晨餐入匕筯，美不儷羹胾。", "神農豈欺予，魏姥有前誌。"]'),
('ca1adfaa-eecd-4748-8e59-25ccea30e049','春蔬','張耒','宋','宋诗','song-poetry','','[]','苣甲如刀圭，蔞蒿未生葉。',96,'全唐诗/poet.song.66000.json','["苣甲如刀圭，蔞蒿未生葉。", "紫芥綠如指，蕪菁苗過茁。", "先生家四壁，食案稍羅列。", "芬芳芼薑芥，每徹有餘啜。", "公侯烹五鼎，一飽厨流血。", "神官計功罪，沉魄受陰殺。", "先生飽捫腹，萬事致瑣屑。", "載覽損益篇，終古守斯說。"]'),
('28a937ff-5388-4106-a7ce-362014b6da9c','食菝葜苗','張耒','宋','宋诗','song-poetry','','[]','江鄉有奇蔬，本草記菝葜。',84,'全唐诗/poet.song.66000.json','["江鄉有奇蔬，本草記菝葜。", "驅風利頑痺，解疫補體節。", "春深土膏肥，紫筍迸玉裂。", "烹之芼薑橘，盡取無可輟。", "應同玉井蓮，已過貓頭茁。", "異時中州去，買子携根撥。", "免令食蔬人，區區美薇蕨。"]'),
('047c4538-ef7a-4c7f-a630-e7b834bfa90e','七日晚同潘郎乘月到欒家觀鶴問石生羚羊角偶有之今早惠角一對良真是也吾藥遂成欣然作詩','張耒','宋','宋诗','song-poetry','','[]','昨宵風月好，携手得吾人。',132,'全唐诗/poet.song.66000.json','["昨宵風月好，携手得吾人。", "南街訪老鶴，夜扣主人門。", "入門未相見，清唳已可聞。", "見我展雙翅，俯啄意甚馴。", "訪藥偶有之，初尚疑未真。", "今晨墮我前，獲此萬里珍。", "披圖驗良是，入藥定有神。", "望茲以試方，輔此老病身。", "嗟我天所窮，一事百苦辛。", "茲遊乃輒遂，造物良已仁。", "因歌遂成詩，往調柯山君。"]'),
('f7e4479a-c74d-47b5-99cd-40920e29da66','食蟹','張耒','宋','宋诗','song-poetry','','[]','世言蟹毒甚，過食風乃乘。',132,'全唐诗/poet.song.66000.json','["世言蟹毒甚，過食風乃乘。", "風淫爲末疾，能敗股與肱。", "我讀本草書，美惡未有憑。", "筋絕不可理，蟹續牢如絙。", "骨萎用蟹補，可使無騫崩。", "凡風待火出，熱甚風乃騰。", "中炎若遇蟹，其快如霜泠。", "俗傳未必妄，但恐殊愛憎。", "本草起東漢，要之出賢能。", "雖失諒不遠，堯跖終殊稱。", "書生自信書，俚說徒營營。"]'),
('79784bc1-7b78-4800-95e5-5d3efc0ddf59','谷鳥','張耒','宋','宋诗','song-poetry','','[]','谷鳥有和聲，杖藜北園路。',72,'全唐诗/poet.song.66000.json','["谷鳥有和聲，杖藜北園路。", "悠悠雪委泥，靄靄春浮樹。", "櫻包欲破紅，梅葩粉墜素。", "幸茲沉疴間，復此賞心遇。", "晴陽山氣昏，積雨溪光露。", "四郊農事起，興懷田野趣。"]'),
('55a0159f-51f3-4916-9fa7-582ed817781f','晝睡','張耒','宋','宋诗','song-poetry','','[]','雨去天已秋，暑歸日猶永。',72,'全唐诗/poet.song.66000.json','["雨去天已秋，暑歸日猶永。", "聊爲清晝眠，度此亭午景。", "蟲鳴籬落晚，地僻鄰里靜。", "起坐晚聞鷄，虛堂無俗聽。", "我非汲汲者，失脚陷機阱。", "天道不吾欺，茲焉遣朝暝。"]'),
('35dc4650-61ef-4462-81cf-9bcd9f6b79e3','十三夜風雨作暑氣頓盡明日與晁郎小飲','張耒','宋','宋诗','song-poetry','','[]','雨洗風掃除，老火不復燎。',72,'全唐诗/poet.song.66000.json','["雨洗風掃除，老火不復燎。", "蓐收行正令，一夕清八表。", "衰骸困燒煮，魂魄始可招。", "東窗美一睡，燈火清自照。", "銀河西南注，促織近堂奧。", "歲晚我何爲，三觴醉清曉。"]'),
('ab2d935a-81fa-4db6-b407-1fccba31982a','寄中山鶴','張耒','宋','宋诗','song-poetry','','[]','矯矯雲外物，本非世所馴。',132,'全唐诗/poet.song.66000.json','["矯矯雲外物，本非世所馴。", "懷安敗爾性，乃與人相親。", "嘎然而長鳴，已愧鴻在雲。", "馬羈當受鞭，泉汲寧辭渾。", "豈無山中友，初不離鷄羣。", "雖無月支料，亦飽松間身。", "嗟我少學古，有道羞賤貧。", "徑出不自愛，蹉跎曳朝紳。", "一爲折腰趨，永愧植杖耘。", "時時猶高談，自喜未緇磷。", "寄語中山鶴，吾與汝知津。"]'),
('fdff2f77-0991-4b6b-8fd0-3aeef10f0067','四月一日同潘何小酌','張耒','宋','宋诗','song-poetry','','[]','今晨一杯酒，相屬送歸春。',60,'全唐诗/poet.song.66000.json','["今晨一杯酒，相屬送歸春。", "明年東風至，何處復迎新。", "懸知柯山下，猶作未知人。", "來者事如夢，未至難預論。", "且使飲此酒，陶然付大鈞。"]'),
('b16d1f5f-2b65-4af0-aeff-bcf4dfc62f8c','春日雜書八首  其一','張耒','宋','宋诗','song-poetry','','[]','長安春雪消，天地一清潤。',72,'全唐诗/poet.song.66000.json','["長安春雪消，天地一清潤。", "牆東風霜枿，新葉如奮迅。", "老懷輕歲月，榮謝置不問。", "平生兒女心，乘間亦鬭進。", "微芳觸鼻界，春意滿方寸。", "却嫌一瓶鉢，事與花不應。"]'),
('e988b492-4781-45f4-b36a-c9d21f409b1b','春日雜書八首  其二','張耒','宋','宋诗','song-poetry','','[]','出門逢一士，韋布污塵土。',72,'全唐诗/poet.song.66000.json','["出門逢一士，韋布污塵土。", "延之升賓階，再拜色低沮。", "問來何所欲，涕下說貧窶。", "其求升斗爾，我亦不能具。", "我窮與君等，祿不飽兒女。", "一事聊自賢，無求差勝汝。"]'),
('116c522e-3e32-4354-955c-7159cbd575b1','春日雜書八首  其三','張耒','宋','宋诗','song-poetry','','[]','年長心益衰，讀書常苦忘。',72,'全唐诗/poet.song.66000.json','["年長心益衰，讀書常苦忘。", "當其欲談說，散墜挽不上。", "詩書非真學，盡記未足尚。", "但憎心辜眼，不爲謹守藏。", "書多墨入腹，無乃與飯妨。", "何如粲然白，廣作酒肉盎。"]'),
('1d51d7f5-4639-4c21-8111-0b63f2e4f0c8','春日雜書八首  其四','張耒','宋','宋诗','song-poetry','','[]','春風無形迹，貧舍亦時至。',120,'全唐诗/poet.song.66000.json','["春風無形迹，貧舍亦時至。", "欲將桃李蹊，易此冰霜地。", "朝陽屋角暖，岸幘散衿袂。", "跡來飭妻子，裘纊且飲費。", "那知事大謬，暮雪卷風至。", "單衣不得出，宛轉眠被袂。", "亦知事不久，頃刻度匪易。", "四鄰同一歡，初不辦此計。", "天公擅萬物，與奪得自恣。", "如何倒寒燠，乃以命爲戲。"]'),
('aa9f1e6e-62de-4870-9a29-e278649d1862','春日雜書八首  其五','張耒','宋','宋诗','song-poetry','','[]','浮名一蹭蹬，萬事付莽鹵。',96,'全唐诗/poet.song.66000.json','["浮名一蹭蹬，萬事付莽鹵。", "惟餘田園心，尚欲學老圃。", "空庭春雪盡，平地灌膏乳。", "買花門前翁，栽插粲可數。", "種之未浹日，晝夜風卷土。", "真須學抱甕，敢信春必雨。", "隔牆見藜藿，氣欲陵棟宇。", "彼獨誰使之，時來遽如許。"]'),
('cb1f056b-e390-41c6-8b11-b1bd21c5f4aa','春日雜書八首  其六','張耒','宋','宋诗','song-poetry','','[]','謂春正無情，乃發桃與李。',72,'全唐诗/poet.song.66000.json','["謂春正無情，乃發桃與李。", "若真有知者，風惡折蘭芷。", "是非一無與，任物自生死。", "德之固已愚，怨者亦豈理。", "有圃畏不蕃，有田憂不美。", "吾環堵蕭然，于何生慍喜。"]'),
('812ff066-589e-4a5a-af9b-bf05451efa00','春日雜書八首  其七','張耒','宋','宋诗','song-poetry','','[]','昨日爲雨備，今晨天乃風。',84,'全唐诗/poet.song.66000.json','["昨日爲雨備，今晨天乃風。", "障風謹自保，通夕雪迷空。", "備一常失計，盡備力不供。", "因之置不爲，拱手受禍凶。", "當爲不可壞，任彼萬變攻。", "築室如金石，何勞計春冬。", "此道簡且安，古來家國同。"]'),
('9e13ccdf-1d3c-46bd-9fef-318b66a1006f','春日雜書八首  其八','張耒','宋','宋诗','song-poetry','','[]','吾聞古夸父，逐日沉虞淵。',72,'全唐诗/poet.song.66000.json','["吾聞古夸父，逐日沉虞淵。", "以日爲可逐，智固未足言。", "徒能出八極，撐突干雲天。", "當其憊且斃，更使兒女憐。", "至弱敗至剛，水波乃飄山。", "誰能守此道，却敵以空弮。"]'),
('74da4257-e9a2-48c3-8d10-ce6d480e9e54','感春十三首  其一','張耒','宋','宋诗','song-poetry','','[]','春郊草木明，秀色如可攬。',84,'全唐诗/poet.song.66000.json','["春郊草木明，秀色如可攬。", "雨餘塵埃少，信馬不知遠。", "黄亂高柳輕，綠鋪新麥短。", "南山逼人來，漲洛清漫漫。", "人家寒食近，桃李暖將綻。", "年豐婦子樂，日出牛羊散。", "携酒莫辭貧，東風花欲爛。"]'),
('312c90d5-1f2e-41f5-baa0-7302d1904592','感春十三首  其二','張耒','宋','宋诗','song-poetry','','[]','寒池冬不流，落葉塞泉罅。',96,'全唐诗/poet.song.66000.json','["寒池冬不流，落葉塞泉罅。", "東風日夕來，春色到山舍。", "杖藜遶東溪，流水清可架。", "疊石引之來，潺潺到深夜。", "平欄朝可鑑，倒影見亭榭。", "清風起修篁，翠鳥亦來下。", "天和人意舒，春暖景物姹。", "歌此濯纓詩，塵埃欲高謝。"]'),
('931d5919-463d-4404-90d7-22893aa42e54','感春十三首  其三','張耒','宋','宋诗','song-poetry','','[]','致酒傍修竹，竹風吹我衣。',96,'全唐诗/poet.song.66000.json','["致酒傍修竹，竹風吹我衣。", "臨觴曷不樂，感此盛與衰。", "昔我池邊柳，北風無完枝。", "春芽忽可擷，弱弱不自持。", "榮枯兩相召，念此能幾時。", "要終必復始，惜我芳華姿。", "自古無如何，悲歌欲何爲。", "聊進杯中物，日醉以爲期。"]'),
('c643a285-1749-4973-b18f-29849e9f2727','感春十三首  其四','張耒','宋','宋诗','song-poetry','','[]','南山如佳人，秀色慰我思。',120,'全唐诗/poet.song.66000.json','["南山如佳人，秀色慰我思。", "微風從東來，清洛摇春漪。", "驅馬出門去，悠悠踏長堤。", "暖日麗花草，微雲渡南溪。", "高丘者誰子，斷裂崗前碑。", "當年豈不偉，泯泯今誰知。", "老翁驅牛耕，墳草半已犁。", "功名但若此，達士觀如遺。", "飲酒復飲酒，勸君無復辭。", "人生百無益，惟有飲庶幾。"]'),
('98455fb5-8f15-4def-a853-f7d3b88a135e','感春十三首  其五','張耒','宋','宋诗','song-poetry','','[]','長嘯視天壤，手撫白玉琴。',96,'全唐诗/poet.song.66000.json','["長嘯視天壤，手撫白玉琴。", "一撫再三歎，誰哉知我音。", "翩翩媚俗子，一仰復一沉。", "靈鳳翔九霄，不顧蒿下禽。", "擇食無果腹，貪藏有良金。", "豈無得與失，兩各行其心。", "窮通亦有命，榮辱迭相尋。", "躬耕儻未輟，聊爲梁父吟。"]'),
('1af853b5-872e-43d7-b19e-5d9a264a90e7','感春十三首  其六','張耒','宋','宋诗','song-poetry','','[]','今晨起何早，盥漱坐南軒。',120,'全唐诗/poet.song.66000.json','["今晨起何早，盥漱坐南軒。", "啄木響高柳，春渠鳴亂泉。", "悠然此時心，默默誰與言。", "焚香閱素書，濯手開靈篇。", "神爽道自合，體和真亦全。", "蕭蕭毛髮輕，浩氣驅昏煩。", "呼童策藜杖，躡露開中園。", "擷彼杞與菊，歸烹助盤飧。", "既飽誰與樂，登高望南山。", "還歸酌美酒，興罷復陶然。"]'),
('bf103a6b-d85a-4e4f-8886-44ca8e07e8a6','感春十三首  其七','張耒','宋','宋诗','song-poetry','','[]','夜醉朝未醒，披衣步南堂。',120,'全唐诗/poet.song.66000.json','["夜醉朝未醒，披衣步南堂。", "折彼曉樹花，嗅此凝露香。", "好鳥鳴我林，聲如韵風篁。", "娟娟屋外杏，顧我如窺牆。", "物色豈不好，人情獨何傷。", "思我二三子，各限天一方。", "無鬐不可游，無羽不可翔。", "耿耿千里心，箕昴互相望。", "結交古所重，義合不能忘。", "離別可奈何，還歸舉予觴。"]'),
('cd4286d6-d562-407c-a399-ce7662c8a524','感春十三首  其八','張耒','宋','宋诗','song-poetry','','[]','浮雲起南山，冉冉朝復雨。',72,'全唐诗/poet.song.66000.json','["浮雲起南山，冉冉朝復雨。", "蒼鳩鳴竹間，兩兩自相語。", "老農城中歸，沽酒飲其婦。", "共言今年麥，新綠已映土。", "去年一尺雪，新澤至已屢。", "豐年坐可待，春服行欲補。"]'),
('81623142-6999-4a89-91af-7f9956a4b6bc','感春十三首  其九','張耒','宋','宋诗','song-poetry','','[]','嗟余尉窮縣，端坐百無慮。',72,'全唐诗/poet.song.66000.json','["嗟余尉窮縣，端坐百無慮。", "幸茲歲豐穰，庶息塵埃步。", "乘間策羸馬，莽莽出門去。", "田原亦可悅，農事藹方布。", "還家有詩書，客至具鷄黍。", "勿復嘆遠游，人生孰非寓。"]'),
('7c1e9fcd-fce0-46dc-8a70-184cb007c6c4','感春十三首  其一○','張耒','宋','宋诗','song-poetry','','[]','漫漫東風來，吹此庭前櫻。',120,'全唐诗/poet.song.66000.json','["漫漫東風來，吹此庭前櫻。", "纍纍綴葩萼，華采日鮮明。", "朝陽助輝爍，好鳥亦和鳴。", "起行不自得，節物傷我情。", "皇天分四時，寒暑無暫停。", "悠然一氣耳，不與人事爭。", "方春感芬敷，秋復惜其零。", "一年能幾何，方寸不暫平。", "念此自知妄，放歌遂遺形。", "達人傲天壤，兒女徒咿嚶。"]'),
('233c78be-be4c-4023-85a0-d029e00d3d12','感春十三首  其一一','張耒','宋','宋诗','song-poetry','','[]','仲春漸燠沐，攄散常遠步。',120,'全唐诗/poet.song.66000.json','["仲春漸燠沐，攄散常遠步。", "獨穿林下蹊，斜轉竹間嶼。", "鳴泉競漱石，迸筍或妨路。", "吹衣信和風，濯足解雙履。", "深行意益愜，默坐憩亦屢。", "野花迎客來，啼鳥驚我去。", "羣鳴投樹鴉，獨下過溪鷺。", "晴霞送斜日，歷歷星已布。", "娟娟新月彎，稍稍山已暮。", "用此遣朝昏，誰謂非尺素。"]'),
('3f00315d-0f15-4f58-93f0-a3fbd47417ca','感春十三首  其一二','張耒','宋','宋诗','song-poetry','','[]','高臺面南山，獨立望空闊。',96,'全唐诗/poet.song.66000.json','["高臺面南山，獨立望空闊。", "東風悠然來，吹我鬢中髮。", "獨遊動遠思，覽物念所悅。", "伊人在千里，山水不可越。", "玉音坐契闊，容華有消歇。", "悲哉音莫致，雜珮空自結。", "羣飛雲間鴻，北羽儼成列。", "愛日崇令德，嘉好當無絕。"]'),
('36c0b3b7-7809-4eb1-beee-dd65a3e8687c','感春十三首  其一三','張耒','宋','宋诗','song-poetry','','[]','沉陰涉春仲，積潦斷行蹟。',96,'全唐诗/poet.song.66000.json','["沉陰涉春仲，積潦斷行蹟。", "浮雲起南山，商羊未休息。", "壅涸無宿滯，芬芳有新摘。", "燈明休間齊，鳥靜山靄夕。", "濁醪足斟酌，野杞柔可食。", "瑶簪脫雛筍，玉縷剸肥鯽。", "冥懷默有契，玩理方自得。", "庶幾達人風，持用慰寂默。"]'),
('3c7cdeec-3249-4384-ac14-2d7f80f986cd','感春','張耒','宋','宋诗','song-poetry','','[]','淹留生白髮，默默又驚春。',288,'全唐诗/poet.song.66000.json','["淹留生白髮，默默又驚春。", "花房與柳萼，三見東風新。", "竟日雨不止，翛翛寒著人。", "擁裘坐閉閣，但與山爐親。", "昔我東南交，藹藹賢簪紳。", "朝晡不相捨，談笑夜達晨。", "清言間嘲謔，侑以肴與尊。", "風花春院靜，霰雪夜爐溫。", "南士多文章，最愛蔡與秦。", "吳僧參寥者，瀟洒出埃塵。", "詩多山水情，野鶴唳秋旻。", "江子貧而廉，鄉黨稱其仁。", "徐子節最苦，五十慕其親。", "頗有豪俠風，時時見於文。", "相逢必痛飲，大盞若鯨吞。", "家無一金資，有口不言貧。", "楚望自南來，贈我佳句頻。", "送我歌百言，爛如張錦茵。", "蔡子不可見，窮泉悶幽魂。", "遺書誰收拾，撫舊心空存。", "僧寥安在哉，江漢一孤鱗。", "徐子益寥落，寂無人薦論。", "周子有書來，乃在吳江濱。", "其餘數子者，影響無由聞。"]'),
('0a49321a-e316-4978-a2ed-40a9ac0d6be7','送晁將之咸平簿','張耒','宋','宋诗','song-poetry','','[]','逢君執經博士堂，見君賜第出明光。',64,'全唐诗/poet.song.66000.json','["逢君執經博士堂，見君賜第出明光。", "俯眉作吏百態惡，豫章參天要雪霜。", "連牆秋雨老藜莧，十日不見已束裝。", "試尋崔丞謝客處，壁間有詩細作行。"]'),
('509f9751-ee3d-4435-baa5-4bd7f2dba1c8','二月十五日','張耒','宋','宋诗','song-poetry','','[]','春風揚塵春日白，衡門向城人寂寂。',64,'全唐诗/poet.song.66000.json','["春風揚塵春日白，衡門向城人寂寂。", "淮陽三月桃李時，街頭時有賣花兒。", "老人卧穩起常晚，欲强出游心獨懶。", "一尊美酒酬芳菲，老大不及年少時。"]'),
('397405de-5caf-483b-8b0a-133792ed1110','通海夜雨寄淮上故人','張耒','宋','宋诗','song-poetry','','[]','黄沙渾渾水滿川，奔流爭岸虎眼漩。',64,'全唐诗/poet.song.66000.json','["黄沙渾渾水滿川，奔流爭岸虎眼漩。", "南來舟子慣風水，萬斛長船如等閑。", "濛濛春雨楊柳濕，漠漠人家雞犬寒。", "道途歸人寄消息，客行安穩近長安。"]'),
('27f95346-edaf-44c2-8c75-e510245fb0e4','泊舟永城西寺下有感','張耒','宋','宋诗','song-poetry','','[]','春水沄沄何處盡，連檣裊裊似當時。',64,'全唐诗/poet.song.66000.json','["春水沄沄何處盡，連檣裊裊似當時。", "昨日橋邊繫船客，南來北去知爲誰。", "他鄉異縣各風物，游子居人長別離。", "歎息東城修竹寺，塵埃漫滅十年題。"]'),
('aa0294d9-3883-4e56-a46d-731047f1958a','伏暑日唯食粥一甌盡屏人事頗逍遙效皮陸體','張耒','宋','宋诗','song-poetry','','[]','烈日炎風鼓大爐，籐床瓦枕閉門居。',64,'全唐诗/poet.song.66000.json','["烈日炎風鼓大爐，籐床瓦枕閉門居。", "屏書居士持齋日，掛壁禪僧問法圖。", "鄰汲滿携泉似乳，新舂旋糴米如珠。", "飽餐饘粥消長夏，況值饑年不敢餘。"]'),
('52921337-5f8c-4cc3-b088-5e98100e3166','壬午正月望夜赴臨汝宿襄城古驛縣有古寺家人輩夜往焚香襄城古邑也可以眺二室地爽塏退之所謂潁水嵩山豁眼明者癸未元夕謫居齊安携家游定惠妙圓承天下大雲東禪蓋出雨夜有感示秬秸','張耒','宋','宋诗','song-poetry','','[]','江城收燈寒寂歷，里巷閉門不復出。',192,'全唐诗/poet.song.66000.json','["江城收燈寒寂歷，里巷閉門不復出。", "蓬茅數屋逐臣廬，門前樵牛卧斜日。", "老人擁褐爐前睡，眼冷不眠思往事。", "去年襄城古驛亭，野縣風埃尋古寺。", "周楚川原氣象存，峴山紫邏秀連雲。", "地留寶鼎周京貴，山拱泥金神岳尊。", "齊安江上漁樵市，誰料今年身到此。", "大江繞郭風濤翻，城中岡壠無平地。", "青紅剪綵挂影燈，漁夫樵婦來相仍。", "短簫急鼓集兒女，叢祠夜半鸕鷀驚。", "浮生夢境何足計，呼童且閉柴門睡。", "百年江上誰得知，竿木隨身聊一戲。"]'),
('74b2fb69-c2db-460c-ae6a-6bbe8116332c','題安州張全翁大夫溪圖','張耒','宋','宋诗','song-poetry','','[]','清溪縈洄流碧玉，散入緣岡萬竿竹。',192,'全唐诗/poet.song.66000.json','["清溪縈洄流碧玉，散入緣岡萬竿竹。", "照春四合錦繡林，干雲直上風霜木。", "主人吾宗行珪璧，解組歸來鬢猶綠。", "祇知林下酒盈樽，不憂門外車推轂。", "靈心內守消冰炭，洗眼旁觀看榮辱。", "造物乘除真有理，却將康健還無欲。", "嗟予放浪已半世，斥逐不去緣微祿。", "六年一夢百憂患，踏雨褰裳過林麓。", "殺雞爲黍固留我，我自奔忙不皇宿。", "乃知風月爲君好，頗覺禽魚憎我俗。", "楚魚楚稻賤如土，老去容身一茅屋。", "他年杖履請卜鄰，與君靜話烹粱粥。"]'),
('0b9cfe1a-31b3-47ef-ac30-017b65b84abc','次韵蘇內相好頭赤','張耒','宋','宋诗','song-poetry','','[]','世無將軍飛食肉，宛馬不來鞭費竹。',64,'全唐诗/poet.song.66000.json','["世無將軍飛食肉，宛馬不來鞭費竹。", "赤駑當御亦偶然，冀北此曹量計谷。", "慚愧蒲梢汗流赤，翻鬣胡風嘶漢日。", "麒麟不合地上行，誰道風雲未經歷。"]'),
('5cf0df05-b1ed-45c0-b137-88fa2d47fc24','題東坡卜算子後','張耒','宋','宋诗','song-poetry','','[]','空江月明魚龍眠，月中孤鴻影翩翩。',64,'全唐诗/poet.song.66000.json','["空江月明魚龍眠，月中孤鴻影翩翩。", "有人清吟立江邊，葛巾藜杖眼窺天。", "夜凉月墮幽蟲急，鴻影翹沙衣露濕。", "仙人采詩作步虛，玉皇飲之碧琳腴。"]'),
('30cfc21d-6a80-4aff-8c88-31e94aaa0591','不雨','張耒','宋','宋诗','song-poetry','','[]','齊安一郡雨不足，稻畦土堅不入穀。',64,'全唐诗/poet.song.66000.json','["齊安一郡雨不足，稻畦土堅不入穀。", "城中赤日風吹沙，老鴉銜火燒竹屋。", "百尺長繩抽井底，井中泥滓多於水。", "潭邊龍祠懸紙錢，誰令霹靂驚龍眠。"]'),
('924c3dc9-c770-4ced-b56c-f66bf1fda23c','厭雨四首  其一','張耒','宋','宋诗','song-poetry','','[]','夜來雨聲倒百川，老農起坐不敢眠。',64,'全唐诗/poet.song.66000.json','["夜來雨聲倒百川，老農起坐不敢眠。", "曰疑漲潦捲屋去，又恐涌水興床前。", "旦視山川一泥濘，流沛千頃新秧田。", "蝦蟆相呼動百千，不念兩股充庖煎。"]'),
('c6f23909-0ea8-404a-953d-448514e540fe','厭雨四首  其二','張耒','宋','宋诗','song-poetry','','[]','霖霪望晴病望汗，里巷呻吟夜達旦。',64,'全唐诗/poet.song.66000.json','["霖霪望晴病望汗，里巷呻吟夜達旦。", "風清日出未敢喜，天公高居龍魚悍。", "夜聲翻盆晝綆縻，百川失性皆上馳。", "乾坤震蕩動植悲，誰居無事爲此嬉。"]'),
('542e2735-31c9-441f-9a72-56d57e687120','厭雨四首  其三','張耒','宋','宋诗','song-poetry','','[]','朝雨沒田夜崩屋，下民何罪罹此毒。',64,'全唐诗/poet.song.66000.json','["朝雨沒田夜崩屋，下民何罪罹此毒。", "天公行雨須命龍，那知人欲食龍肉。", "玄雲幕天不可决，日烏戢翼愁暘谷。", "區區昏墊未足憂，當念波濤翻地軸。"]'),
('e3abef40-25bb-48d3-ae90-aa0cd6c0155e','厭雨四首  其四','張耒','宋','宋诗','song-poetry','','[]','柯山老人家四壁，深居閉門不下席。',64,'全唐诗/poet.song.66000.json','["柯山老人家四壁，深居閉門不下席。", "日補丹田氣三咽，自言茲味勝玉食。", "無田無屋一空囊，不管門前水三尺。", "有錢沽酒便不憂，會見天清還白日。"]'),
('5e28b373-bbd3-459e-a6d9-1652edc3b38f','夢游陳州柳河覺而作','張耒','宋','宋诗','song-poetry','','[]','虎豹九關未敢望，里門舊游如可尋。',64,'全唐诗/poet.song.66000.json','["虎豹九關未敢望，里門舊游如可尋。", "夢到城西古壕水，倚天高柳萬黄金。", "叢祠之南我舊圃，蔬甲若若春泥深。", "睡覺啼禽自相問，經年他鄉何滯淫。"]'),
('74eb8cc4-c3f7-4344-8641-1b336d12a8cb','新正','張耒','宋','宋诗','song-poetry','','[]','春風浩浩春陽盡，老木生芽綠如豆。',64,'全唐诗/poet.song.66000.json','["春風浩浩春陽盡，老木生芽綠如豆。", "古巢老烏聲鴉鴉，南陂雨乾麥將秀。", "人家寒食無一月，青箬蒸魚競時節。", "白衫紫領來自田，縣官呼我要青錢。"]'),
('4c2a3818-8afb-4afc-90f9-bbee8a48907b','苦寒二首  其一','張耒','宋','宋诗','song-poetry','','[]','二月八日寒未已，山城雨過浄如洗。',64,'全唐诗/poet.song.66000.json','["二月八日寒未已，山城雨過浄如洗。", "城門樵漁不復來，市中屐齒響長街。", "老翁一杯百不知，酒酣放歌視羣兒。", "句芒當權不用事，玄冥功成徒爾爲。"]'),
('8e1c1ada-991d-4ac1-94a5-8df7e59225a0','苦寒二首  其二','張耒','宋','宋诗','song-poetry','','[]','山城新炭賤於土，老翁守壚朝復暮。',64,'全唐诗/poet.song.66000.json','["山城新炭賤於土，老翁守壚朝復暮。", "時傾牆下一杯酒，不怕簷前三尺雨。", "共言麥好歲當熟，里巷往來聞好語。", "老大湯餠百不憂，折脚鐺中足烹煮。"]'),
('17a83f2a-7719-4ca4-be1d-c020f853aae4','贈馬十二全玉沿檄過楚頃刻而別','張耒','宋','宋诗','song-poetry','','[]','我離海邊方季夏，子時別我西亭下。',224,'全唐诗/poet.song.66000.json','["我離海邊方季夏，子時別我西亭下。", "是時積雨河水深，却看孤舟放清夜。", "爾來忽忽冬已闌，歲晚荒凉學官舍。", "那知復與子携手，猶能頃刻聽清話。", "來時綠樹今黄葉，須信丹顔暗中化。", "別離易得當重惜，歲月難留足悲吒。", "人生坎軻多憂娛，萬事紛紛少休暇。", "况子飄泊不可常，幾度相逢即衰謝。", "功名有命何足求，富貴無常求亦乍。", "隋珠彈雀雖有獲，纖塵未補千金價。", "我於世事甘不學，久師壁觀依僧社。", "辱君指我曹溪源，行雖未至寧辭駕。", "君如有志反丘壑，我即求田買桑柘。", "卜鄰丈室聽談禪，更問老農求學稼。"]'),
('40ce152f-bf92-4395-899b-6b971733da44','別梅','張耒','宋','宋诗','song-poetry','','[]','宦遊到處即爲家，况我遷謫來天涯。',128,'全唐诗/poet.song.66000.json','["宦遊到處即爲家，况我遷謫來天涯。", "三年假館主人屋，忽忽屢見新梅花。", "那知今冬當去此，十月已見凌霜葩。", "繞之百匝未易別，對我脈脈如含嗟。", "懸知客去門復掩，亭沼人散啼昏鴉。", "朝風吹香散寂歷，夜月照影低橫斜。", "嗟我明年復何處，東州旱野連桑麻。", "相思時有夢魂到，極目南望空烟霞。"]'),
('fdc76bf9-8bbb-45d6-bba0-d5b0256b83b1','初夏','張耒','宋','宋诗','song-poetry','','[]','南風吹筍成修竹，園林一番新陰綠。',64,'全唐诗/poet.song.66000.json','["南風吹筍成修竹，園林一番新陰綠。", "足愁多病少歡娛，感時念遠傷幽獨。", "遙山林外知何處，倦客樓頭空極目。", "悲笳三疊閉江城，娟娟新月啼烏宿。"]'),
('376ff287-f5bc-4748-908f-1fe345b1226c','和應之蝎虎','張耒','宋','宋诗','song-poetry','','[]','蝎虎捕蠅君歎息，爾胡縱蝎蠅遭食。',67,'全唐诗/poet.song.66000.json','["蝎虎捕蠅君歎息，爾胡縱蝎蠅遭食。", "畏難侮易真可尤，能捕飛蠅猶有益。", "君不見世上虛名相借與，號以千鈞實無縷。", "豈惟無益害從旃，搏繩之虎猶爲賢。"]'),
('14e2ce18-508a-4918-8956-05a178041713','寒夜','張耒','宋','宋诗','song-poetry','','[]','暗空無星雲抹漆，邑犬吠野人履霜。',64,'全唐诗/poet.song.66000.json','["暗空無星雲抹漆，邑犬吠野人履霜。", "歲云暮矣風落木，夜如何其斗插江。", "屋頭眠雞正寂寂，野縣嚴鼓先逢逢。", "摩挲老面起搆火，春色床頭酒滿缸。"]'),
('369f3e55-90b1-4bf2-85a5-14d2edc85579','雪中狂言五首  其一','張耒','宋','宋诗','song-poetry','','[]','江鄉密雪常在春，異哉今臘已再白。',64,'全唐诗/poet.song.66000.json','["江鄉密雪常在春，異哉今臘已再白。", "風嚴無聲掠樹過，茅簷飛霰鳴策策。", "老農飽食莫畏寒，天意在汝田中麥。", "我雖無田助爾喜，來歲不憂湯餠窄。"]'),
('e1254a07-41a6-4a71-973c-38e079f7dfbe','雪中狂言五首  其二','張耒','宋','宋诗','song-poetry','','[]','今春齊安大疾疫，閭里老弱死籍籍。',64,'全唐诗/poet.song.66000.json','["今春齊安大疾疫，閭里老弱死籍籍。", "篾繩蘆蓆肩兩夫，繞郭纍纍瘞千百。", "玄冥一日行正令，癘氣入地應千尺。", "異鄉身健百不憂，有錢但知沽酒喫。"]'),
('b47f02bf-d0b3-44e3-9740-1b5cc054dae6','雪中狂言五首  其三','張耒','宋','宋诗','song-poetry','','[]','我家中州食嗜麵，長羅如船磑如電。',64,'全唐诗/poet.song.66000.json','["我家中州食嗜麵，長羅如船磑如電。", "爛銀白璧照中厨，膳夫調和隨百變。", "江鄉種麥幾數粒，强進腥魚蒸糲飯。", "雪深麥好定豐登，明年一飽償吾願。"]'),
('6fcee8a8-0347-42e3-806a-a9b5465e0e70','雪中狂言五首  其四','張耒','宋','宋诗','song-poetry','','[]','請說吾鄉人種麥，漫山亙野頃千百。',64,'全唐诗/poet.song.66000.json','["請說吾鄉人種麥，漫山亙野頃千百。", "北風寒嚴大澤乾，一臘何啻見三白。", "春泥冰消土脈動，壠畝漸縱牛羊續。", "街頭作餠大如槃，一歲衣食事已畢。"]'),
('e3344e7c-1a18-49b5-b96d-7c0cab5de064','雪中狂言五首  其五','張耒','宋','宋诗','song-poetry','','[]','故園陳墟太昊祠，臘雪消後融春泥。',64,'全唐诗/poet.song.66000.json','["故園陳墟太昊祠，臘雪消後融春泥。", "韭芽苣甲初出土，春槃飣鬬如棼絲。", "里閭經過厭此物，糖䭔寒具方交馳。", "江南魚稻豈不美，長年謫居長土思。"]'),
('b81f4dfa-5df7-47a6-b711-20183248f297','聞紅鶴有感','張耒','宋','宋诗','song-poetry','','[]','東風吹曉麥青青，柯山樹頭紅鶴嗚。',96,'全唐诗/poet.song.66000.json','["東風吹曉麥青青，柯山樹頭紅鶴嗚。", "窗間夢斷客歎息，憶我去年臨汝城。", "平池朱閣花如雪，峴山少室兩奇絕。", "豈知崎嶇黄土崗，茅屋蘆籬風雨折。", "殷勤寄語望嵩樓，此身强健會重游。", "陳跡再尋難料得，正如三到舊黄州。"]'),
('157082d9-b4bb-45c6-a49c-761c08841435','聞蘇先生除校書郎喜而爲詩并招王子中','張耒','宋','宋诗','song-poetry','','[]','績溪仙翁若秋鶴，有喙不向腥羶啄。',256,'全唐诗/poet.song.66000.json','["績溪仙翁若秋鶴，有喙不向腥羶啄。", "幾年戢翼大江南，下看紛紛飛燕雀。", "親携杖拂呵禪祖，自伐松根出靈藥。", "世人真自爲公忙，公寧有意人間樂。", "嗣皇繼明登俊彥，詔遣讎書天祿閣。", "江山氣象滿收貯，傾倒歸來開萬橐。", "咸韶無聲嗟已久，野鼓羌弦自宮角。", "當令鸞鳳見文章，却遣丘陵仰山嶽。", "王郎蕭蕭好文筆，一世清名推衛樂。", "嶺頭梅發始辭家，坐見長安秋葉落。", "滯留窮縣許過我，季心不負千金諾。", "何爲歲晚尚遲留，庭下寒篁還解籜。", "我老栖栖亦何事，一官未足充藜藿。", "讀書把筆工無益，執板折腰心已怍。", "頑疏一味難鞭警，妙道多生欲穿鑿。", "惟君所事與我同，他日相從鄭君學。"]'),
('e7cfa28c-4296-4319-9484-319464905bfc','偶書三首  其一','張耒','宋','宋诗','song-poetry','','[]','秋陰漫漫幾千里，赤壁磯前天接水。',64,'全唐诗/poet.song.66000.json','["秋陰漫漫幾千里，赤壁磯前天接水。", "連檣接舵不復行，老魚擘波時出戲。", "黄橙紫栗收如積，青錢買酒不堪惜。", "北人歲久厭南餐，山邊有路何時還。"]'),
('5d8bcbad-9d3e-48c1-9fb6-0a69ce747fb8','偶書三首  其二','張耒','宋','宋诗','song-poetry','','[]','窮愁晝夜陰如一，夜不見星朝蔽日。',64,'全唐诗/poet.song.66000.json','["窮愁晝夜陰如一，夜不見星朝蔽日。", "枯疇已穫大野空，怒江未落連洲沒。", "長魚潑剌不受釣，漁子高眠守蓬蓽。", "紫髯舊宮誰復游，鼎峙雄心久蕭瑟。"]'),
('c41f1d41-d22d-47d3-9d87-2eb5c6201339','偶書三首  其三','張耒','宋','宋诗','song-poetry','','[]','周郎戰處滄江回，魚龍蕩潏山石摧。',64,'全唐诗/poet.song.66000.json','["周郎戰處滄江回，魚龍蕩潏山石摧。", "荆州艨艟莫舉檝，走君不勞一炬灰。", "當年雄豪誰復在，喬木荒烟忽千載。", "蘄州截竹作笛材，一寫山川萬古哀。"]'),
('3c89ab96-0464-4341-949c-d4843ce05ff6','感春','張耒','宋','宋诗','song-poetry','','[]','我愛沙邊雙白鷗，飛鳴相樂還相求。',64,'全唐诗/poet.song.66000.json','["我愛沙邊雙白鷗，飛鳴相樂還相求。", "往來飲啄性如一，異類不至心無憂。", "我來窮山無與友，雖有接納非吾儔。", "人生從類乃爲樂，强言笑語歡何由。"]'),
('f3c1a0b5-69b9-47b6-a961-4342751d752b','對酒奉懷无咎二首  其一','張耒','宋','宋诗','song-poetry','','[]','城門失火池魚窮，樹頭風聲酒榼空。',64,'全唐诗/poet.song.66000.json','["城門失火池魚窮，樹頭風聲酒榼空。", "雖貧家婦有旨蓄，一一可口不待豐。", "往來曳杖兩足健，醉後哦詩雙頰紅。", "最憶南都晁別駕，高歌大笑聲如鐘。"]'),
('07313d65-a848-4fce-9fa5-f46d5fab7a2c','對酒奉懷无咎二首  其二','張耒','宋','宋诗','song-poetry','','[]','我兄改秩令新昌，相望雖遠同江外。',64,'全唐诗/poet.song.66000.json','["我兄改秩令新昌，相望雖遠同江外。", "君家兄弟數如我，曹南好在龐眉弟。", "官微無利沾骨肉，兩處强健差自慰。", "近來老子還破禪，一女咿啞猶未睟。"]'),
('faae44f4-b703-42c2-b483-c3fa85e57759','醉郡圃二首  其一','張耒','宋','宋诗','song-poetry','','[]','東風流園開百花，繁紅釅白如晴霞。',64,'全唐诗/poet.song.66000.json','["東風流園開百花，繁紅釅白如晴霞。", "主人殷勤勸客飲，我爲滿釂酢以華。", "游人酒客興未足，舉首白日西南斜。", "人生有酒不肯飲，百年醒坐何爲耶。"]'),
('43d5f60d-d9ed-465a-b36b-13efcc7da1bb','醉郡圃二首  其二','張耒','宋','宋诗','song-poetry','','[]','驅童晨摘承露花，薦以玉盤濡井華。',64,'全唐诗/poet.song.66000.json','["驅童晨摘承露花，薦以玉盤濡井華。", "誰云離本即憔悴，持玩入手意有加。", "爲之致酒就几案，影落酒底杯浮葩。", "平生看花常不足，肯使容易親塵沙。"]'),
('7be0d4be-b692-4092-aecc-9f0a9f540cc5','秋園雜感','張耒','宋','宋诗','song-poetry','','[]','只今枯條罥衰蔓，異時密葉如翠葆。',64,'全唐诗/poet.song.66000.json','["只今枯條罥衰蔓，異時密葉如翠葆。", "執斤之子久睥睨，簸米待薪已除竈。", "寄言青雲富貴人，金朱能得幾時好。", "是非榮辱百不知，却輸頑鈍柯山老。"]'),
('b9452eef-a559-4f90-9869-511835973255','孝感縣','張耒','宋','宋诗','song-poetry','','[]','蕭索江干縣，林端見客檣。',48,'全唐诗/poet.song.66000.json','["蕭索江干縣，林端見客檣。", "山川錯吳楚，人物混荆楊。", "風略寒蘆陣，雲迷夕鳥行。", "故鄉同見月，誰記白頭郎。"]'),
('2ba36278-d419-4738-99b1-d7fe669d7057','春寒二首  其一','張耒','宋','宋诗','song-poetry','','[]','星霜殘臘過，霰雪一冬頻。',48,'全唐诗/poet.song.66000.json','["星霜殘臘過，霰雪一冬頻。", "雲重常昏晝，寒多更入春。", "晚風捎翠暮，輕雨斂微塵。", "滿酌山樽酒，驅愁爾最親。"]'),
('37ccf401-cded-48da-8ca0-3c595ba97936','春寒二首  其二','張耒','宋','宋诗','song-poetry','','[]','漠漠陰還合，迢迢日自長。',48,'全唐诗/poet.song.66000.json','["漠漠陰還合，迢迢日自長。", "雲容將雨露，山意自風霜。", "欄甲青辭土，園枝笑倚牆。", "薄寒能幾許，春雨滿池塘。"]'),
('318ee50e-de81-4842-b50b-ee7009c1df48','春晴','張耒','宋','宋诗','song-poetry','','[]','溪流清欲漲，山雪白仍鋪。',48,'全唐诗/poet.song.66000.json','["溪流清欲漲，山雪白仍鋪。", "耕隴晴羅雉，春渠暖日蔬。", "禽魚隨處樂，草木向陽舒。", "酒病年來甚，高眠懶著書。"]'),
('d3381804-ab3f-424c-a400-7595dcf42833','傷春','張耒','宋','宋诗','song-poetry','','[]','山城夜來雨，卧病惜殘春。',48,'全唐诗/poet.song.66000.json','["山城夜來雨，卧病惜殘春。", "暗暗鳥啼樹，飄飄花去人。", "地偏佳客斷，官冷酒錢貧。", "乘興還騎馬，田家樂更真。"]'),
('999b272e-ff15-495d-9002-3d846e6d3fe6','近清明二首  其一','張耒','宋','宋诗','song-poetry','','[]','斜日去不駐，好風來有情。',48,'全唐诗/poet.song.66000.json','["斜日去不駐，好風來有情。", "江城過風雨，花木近清明。", "水樹閒照影，山禽時引聲。", "吾年行老矣，淹泊蹇何成。"]'),
('7e3ddd50-a457-462e-a698-44ba938eb36c','近清明二首  其二','張耒','宋','宋诗','song-poetry','','[]','冉冉春向老，昏昏日復斜。',48,'全唐诗/poet.song.66000.json','["冉冉春向老，昏昏日復斜。", "鮮歡常止酒，不睡更烹茶。", "幡起烟中剎，鷄鳴林外家。", "陳王鬭雞道，風柳不勝斜。"]'),
('c6826102-5249-4b9c-8b83-212779492154','青春','張耒','宋','宋诗','song-poetry','','[]','青春忽妍好，半嶺麗朝陽。',48,'全唐诗/poet.song.66000.json','["青春忽妍好，半嶺麗朝陽。", "谷鳥喜相見，園花明曉妝。", "閑居耽道味，吟眺惜風光。", "扣戶有佳客，悠然三舉觴。"]'),
('a01dd9fd-00d1-48f3-a139-6a2b1bce8480','寒食後數日方持齋誦經而東園遊人甚盛因而賦此','張耒','宋','宋诗','song-poetry','','[]','芳物忽過半，寒食已闌珊。',48,'全唐诗/poet.song.66000.json','["芳物忽過半，寒食已闌珊。", "園靜鳴鳥下，花稀新葉繁。", "焚香翻貝葉，謝客掩柴關。", "止酒方清坐，畦蔬助晚餐。"]'),
('18b5d8c2-0236-47dc-8a30-8c48eb806311','寒食日贈同飲者','張耒','宋','宋诗','song-poetry','','[]','春城風雨後，花落滿人家。',48,'全唐诗/poet.song.66000.json','["春城風雨後，花落滿人家。", "宿潤留芳草，晴輝上曉霞。", "園林正寒食，樽酒對年華。", "一笑相逢地，功名莫嘆嗟。"]'),
('e24da84f-5e85-43ad-95ca-74bf2854b9c3','暮春書事四首  其一','張耒','宋','宋诗','song-poetry','','[]','冉冉春將老，悠悠晝掩關。',48,'全唐诗/poet.song.66000.json','["冉冉春將老，悠悠晝掩關。", "鳩鳴高柳暗，雨細廣庭閑。", "塵榻談無客，風簾望有山。", "啣泥新燕子，一一及時還。"]'),
('fb0c8c26-7cd1-4fb4-9f3d-c8753b7bb7c1','暮春書事四首  其二','張耒','宋','宋诗','song-poetry','','[]','漠漠山雲合，簷風透薄帷。',48,'全唐诗/poet.song.66000.json','["漠漠山雲合，簷風透薄帷。", "柳藏陰後絮，櫻壓雨中枝。", "坐暖晨杯罷，香濃午睡時。", "薄寒猶故在，再取紫貂披。"]'),
('9a658fb1-d795-4261-ac6d-f1e1a46db315','暮春書事四首  其三','張耒','宋','宋诗','song-poetry','','[]','冉冉春將老，遲遲日正長。',48,'全唐诗/poet.song.66000.json','["冉冉春將老，遲遲日正長。", "露花低曉架，風絮集閑堂。", "水暖荷爭出，杯寒杏已嘗。", "芳菲值窮谷，嗟負少年狂。"]'),
('569f8dde-1347-473a-a8f7-0feacae83396','暮春書事四首  其四','張耒','宋','宋诗','song-poetry','','[]','林花飛已久，芳草雨餘長。',48,'全唐诗/poet.song.66000.json','["林花飛已久，芳草雨餘長。", "人靜槐庭午，簾斜竹院凉。", "沾泥新筍白，封蠟煮醪香。", "莫厭殘春醉，流鶯勸舉觴。"]'),
('725f3f2c-f963-4d9d-b9ed-3430b482b35d','春暮有感二首  其一','張耒','宋','宋诗','song-poetry','','[]','午枕消暗永，春裘御曉清。',48,'全唐诗/poet.song.66000.json','["午枕消暗永，春裘御曉清。", "砌紅多近采，園綠有深鳴。", "窗破斜光入，爐消斷碧橫。", "白頭爲吏苦，高卧笑浮生。"]'),
('34201107-c0b0-4be0-aede-d92bea51bf14','春暮有感二首  其二','張耒','宋','宋诗','song-poetry','','[]','江城春雨暗，客舍夜燈明。',48,'全唐诗/poet.song.66000.json','["江城春雨暗，客舍夜燈明。", "搆火添香炷，擁衾聞竹聲。", "微明旁舍火，斷續遠樓更。", "何處離羣鳥，孤飛深夜鳴。"]'),
('4f19c78f-ac6b-4483-be27-f81da6b1ca51','感春二首  其一','張耒','宋','宋诗','song-poetry','','[]','不覺悠悠過，東風換故年。',48,'全唐诗/poet.song.66000.json','["不覺悠悠過，東風換故年。", "青春消霰雪，白日滿山川。", "草綠飄梅地，江平去雁天。", "故園桃李動，東望每依然。"]');
